{
  "name": "V4 Commercial Intelligence",
  "description": "A dynamic commercial dashboard for V4 Company tracking MRR, Fixed Scope revenue, and Funnel performance with role-based access control."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DealStatus {
  SIGNED = 'Signed',
  PENDING = 'Pending_Na_Rua',
  LOST = 'Lost'
}

export enum DealType {
  RECURRING = 'Recurring',
  FIXED = 'Fixed',
  MIXED = 'Mixed'
}

export enum FunnelType {
  OUTBOUND = 'Outbound',
  LEAD_BROKER = 'LeadBroker',
  INDICATION = 'Indication'
}

export interface MonthData {
  id: string;
  name: string; // e.g., "October"
  year: number;
  slug: string; // e.g., "oct-2025"
  working_days: number;
  unit_goal_mrr: number;
  matrix_goal_mrr: number;
}

export interface Deal {
  id: string;
  month_id: string;
  client_name: string;
  status: DealStatus;
  type: DealType;
  value_mrr: number;
  value_fixed: number;
  acquisition_channel: FunnelType;
  sign_date?: string;
}

export interface FunnelStats {
  id: string;
  month_id: string;
  funnel_type: FunnelType;
  leads: number;
  connections: number;
  meetings_scheduled: number;
  meetings_realized: number;
  sales: number;
  invested_amount: number; // For CAC
}

export interface UserProfile {
  email: string;
  role: 'admin' | 'viewer';
}

export const ADMIN_EMAILS = [
  'vinicius.hanzava@v4company.com',
  'gabriel.prates@v4company.com'
];

import { createClient } from '@supabase/supabase-js';

// NOTE: These would typically come from import.meta.env
// For this demo code generator, we are setting up the structure.
const SUPABASE_URL = process.env.REACT_APP_SUPABASE_URL || 'https://xyz.supabase.co';
const SUPABASE_ANON_KEY = process.env.REACT_APP_SUPABASE_ANON_KEY || 'your-anon-key';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

import React, { useState } from 'react';
import { UserProfile, ADMIN_EMAILS } from '../types';
import { Lock, ShieldCheck, AlertCircle } from 'lucide-react';

interface AuthGuardProps {
  onLogin: (user: UserProfile) => void;
  children: React.ReactNode;
}

export const AuthGuard: React.FC<AuthGuardProps> = ({ onLogin, children }) => {
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const lowerEmail = email.toLowerCase();

    // Domain Check
    if (!lowerEmail.endsWith('@v4company.com')) {
      setError('Access Restricted: Only @v4company.com emails allowed.');
      return;
    }

    // Role Check
    const role = ADMIN_EMAILS.includes(lowerEmail) ? 'admin' : 'viewer';

    setIsAuthenticated(true);
    onLogin({ email: lowerEmail, role });
  };

  if (isAuthenticated) {
    return <>{children}</>;
  }

  return (
    <div className="min-h-screen bg-neutral-900 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
        <div className="bg-v4-red h-2 w-full"></div>
        <div className="p-8">
          <div className="flex justify-center mb-6">
            <div className="bg-red-50 p-3 rounded-full">
              <Lock className="w-8 h-8 text-v4-red" />
            </div>
          </div>

          <h2 className="text-2xl font-bold text-center text-gray-800 mb-2">
            Commercial Intelligence
          </h2>
          <p className="text-center text-gray-500 mb-8 text-sm">
            Restricted Access. Please identify yourself.
          </p>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Corporate Email
              </label>
              <input
                type="email"
                required
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-v4-red focus:border-transparent outline-none transition-all"
                placeholder="name@v4company.com"
                value={email}
                onChange={(e) => {
                  setEmail(e.target.value);
                  setError('');
                }}
              />
            </div>

            {error && (
              <div className="flex items-center gap-2 text-red-600 text-sm bg-red-50 p-3 rounded-lg">
                <AlertCircle className="w-4 h-4" />
                {error}
              </div>
            )}

            <button
              type="submit"
              className="w-full bg-v4-red text-white font-bold py-3 rounded-lg hover:bg-red-700 transition-colors flex items-center justify-center gap-2"
            >
              <ShieldCheck className="w-5 h-5" />
              Access Dashboard
            </button>
          </form>

          <div className="mt-6 text-center text-xs text-gray-400">
            For demo purposes, try: <br/>
            <span className="font-mono text-gray-600">vinicius.hanzava@v4company.com</span> (Admin)<br/>
            <span className="font-mono text-gray-600">user@v4company.com</span> (Viewer)
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { MonthData, Deal, DealStatus } from '../types';
import { DollarSign, TrendingUp, Target, Briefcase } from 'lucide-react';

interface ExecutiveSummaryProps {
  month: MonthData;
  deals: Deal[];
}

export const ExecutiveSummary: React.FC<ExecutiveSummaryProps> = ({ month, deals }) => {
  // 1. Calculate Signed MRR
  const signedMRR = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_mrr, 0);

  // 2. Calculate Fixed Revenue (Signed)
  const signedFixed = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_fixed, 0);

  // 3. Projected (Signed + Pending weighted). Simple version: Just sum pending.
  const pendingMRR = deals
    .filter(d => d.status === DealStatus.PENDING)
    .reduce((sum, d) => sum + d.value_mrr, 0);

  const projectedMRR = signedMRR + pendingMRR;

  // 4. Progress Calculations
  const unitProgress = (signedMRR / month.unit_goal_mrr) * 100;
  const matrixProgress = (signedMRR / month.matrix_goal_mrr) * 100;

  const getProgressColor = (percent: number) => {
    if (percent < 50) return 'bg-red-500';
    if (percent < 80) return 'bg-yellow-500';
    return 'bg-green-500';
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
      {/* Card 1: Signed MRR */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
        <div className="flex justify-between items-start mb-4">
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Actual MRR</p>
            <h3 className="text-2xl font-bold text-gray-900 mt-1">{formatCurrency(signedMRR)}</h3>
          </div>
          <div className="bg-red-50 p-2 rounded-lg">
            <DollarSign className="w-6 h-6 text-v4-red" />
          </div>
        </div>
        <div className="text-sm text-gray-500">
          Fixed Rev: <span className="font-semibold text-gray-700">{formatCurrency(signedFixed)}</span>
        </div>
      </div>

      {/* Card 2: Projected MRR */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
        <div className="flex justify-between items-start mb-4">
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Projected MRR</p>
            <h3 className="text-2xl font-bold text-gray-900 mt-1">{formatCurrency(projectedMRR)}</h3>
          </div>
          <div className="bg-blue-50 p-2 rounded-lg">
            <TrendingUp className="w-6 h-6 text-blue-600" />
          </div>
        </div>
        <div className="text-sm text-gray-500">
          Pipeline: <span className="font-semibold text-gray-700">{formatCurrency(pendingMRR)}</span>
        </div>
      </div>

      {/* Card 3: Unit Goal */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
        <div className="flex justify-between items-start mb-2">
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Unit Goal</p>
            <h3 className="text-xl font-bold text-gray-900 mt-1">{formatCurrency(month.unit_goal_mrr)}</h3>
          </div>
          <Target className="w-5 h-5 text-gray-400" />
        </div>
        <div>
          <div className="flex justify-between text-xs text-gray-500 mb-1">
            <span>Progress</span>
            <span>{unitProgress.toFixed(1)}%</span>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-2.5">
            <div className={`h-2.5 rounded-full ${getProgressColor(unitProgress)}`} style={{ width: `${Math.min(unitProgress, 100)}%` }}></div>
          </div>
        </div>
      </div>

      {/* Card 4: Matrix Goal */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
        <div className="flex justify-between items-start mb-2">
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Matrix Goal</p>
            <h3 className="text-xl font-bold text-gray-900 mt-1">{formatCurrency(month.matrix_goal_mrr)}</h3>
          </div>
          <Briefcase className="w-5 h-5 text-gray-400" />
        </div>
        <div>
          <div className="flex justify-between text-xs text-gray-500 mb-1">
            <span>Progress</span>
            <span>{matrixProgress.toFixed(1)}%</span>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-2.5">
            <div className={`h-2.5 rounded-full ${getProgressColor(matrixProgress)}`} style={{ width: `${Math.min(matrixProgress, 100)}%` }}></div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Deal, DealStatus, DealType, UserProfile } from '../types';
import { MoreHorizontal, Calendar, Briefcase, RefreshCw } from 'lucide-react';

interface DealKanbanProps {
  deals: Deal[];
  user: UserProfile;
}

const DealCard: React.FC<{ deal: Deal; isAdmin: boolean }> = ({ deal, isAdmin }) => {
  const isRecurring = deal.type === DealType.RECURRING || deal.type === DealType.MIXED;
  const isFixed = deal.type === DealType.FIXED || deal.type === DealType.MIXED;

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  return (
    <div className={`bg-white p-4 rounded-lg shadow-sm border border-gray-100 mb-3 hover:shadow-md transition-shadow group relative ${isAdmin ? 'cursor-grab' : ''}`}>
      {isAdmin && (
        <button className="absolute top-3 right-3 text-gray-300 hover:text-gray-600 opacity-0 group-hover:opacity-100 transition-opacity">
          <MoreHorizontal className="w-5 h-5" />
        </button>
      )}

      <div className="flex flex-wrap gap-2 mb-2">
        {isRecurring && (
           <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-blue-100 text-blue-800">
             <RefreshCw className="w-3 h-3 mr-1" /> MRR
           </span>
        )}
        {isFixed && (
           <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-purple-100 text-purple-800">
             <Briefcase className="w-3 h-3 mr-1" /> Fixed
           </span>
        )}
      </div>

      <h4 className="font-bold text-gray-900 mb-2 truncate">{deal.client_name}</h4>

      <div className="space-y-1">
        {deal.value_mrr > 0 && (
          <div className="flex justify-between text-sm">
            <span className="text-gray-500">Recurring:</span>
            <span className="font-semibold text-gray-800">{formatCurrency(deal.value_mrr)}</span>
          </div>
        )}
        {deal.value_fixed > 0 && (
          <div className="flex justify-between text-sm">
            <span className="text-gray-500">Scope:</span>
            <span className="font-semibold text-gray-800">{formatCurrency(deal.value_fixed)}</span>
          </div>
        )}
      </div>

      <div className="mt-3 pt-2 border-t border-gray-50 flex items-center justify-between">
         <span className="text-xs text-gray-400 flex items-center">
            {deal.acquisition_channel}
         </span>
         {deal.sign_date && (
           <span className="text-xs text-gray-400 flex items-center">
             <Calendar className="w-3 h-3 mr-1" />
             {new Date(deal.sign_date).toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit'})}
           </span>
         )}
      </div>
    </div>
  );
};

export const DealKanban: React.FC<DealKanbanProps> = ({ deals, user }) => {
  const isAdmin = user.role === 'admin';
  const pendingDeals = deals.filter(d => d.status === DealStatus.PENDING);
  const signedDeals = deals.filter(d => d.status === DealStatus.SIGNED);

  const calculateTotal = (list: Deal[]) => list.reduce((acc, curr) => acc + curr.value_mrr + curr.value_fixed, 0);

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
      {/* Column: Pending */}
      <div className="bg-gray-50 p-4 rounded-xl flex flex-col h-full max-h-[600px]">
        <div className="flex justify-between items-center mb-4 px-2">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
            <h3 className="font-bold text-gray-700">Pending (Na Rua)</h3>
            <span className="bg-gray-200 text-gray-600 px-2 py-0.5 rounded-full text-xs font-bold">{pendingDeals.length}</span>
          </div>
          <span className="text-xs font-semibold text-gray-500">
            Est. Total: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(calculateTotal(pendingDeals))}
          </span>
        </div>
        <div className="flex-1 overflow-y-auto pr-2">
          {pendingDeals.map(deal => (
            <DealCard key={deal.id} deal={deal} isAdmin={isAdmin} />
          ))}
          {pendingDeals.length === 0 && (
            <div className="text-center py-10 text-gray-400 text-sm italic">No pending deals.</div>
          )}
        </div>
      </div>

      {/* Column: Signed */}
      <div className="bg-gray-50 p-4 rounded-xl flex flex-col h-full max-h-[600px]">
        <div className="flex justify-between items-center mb-4 px-2">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-green-500"></div>
            <h3 className="font-bold text-gray-700">Signed (Assinados)</h3>
            <span className="bg-gray-200 text-gray-600 px-2 py-0.5 rounded-full text-xs font-bold">{signedDeals.length}</span>
          </div>
          <span className="text-xs font-semibold text-gray-500">
             Total: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(calculateTotal(signedDeals))}
          </span>
        </div>
        <div className="flex-1 overflow-y-auto pr-2">
          {signedDeals.map(deal => (
            <DealCard key={deal.id} deal={deal} isAdmin={isAdmin} />
          ))}
          {signedDeals.length === 0 && (
             <div className="text-center py-10 text-gray-400 text-sm italic">No signed deals yet.</div>
          )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { FunnelStats, FunnelType } from '../types';
import { Users, Phone, CalendarCheck, CheckCircle, ArrowRight } from 'lucide-react';

interface FunnelDashboardProps {
  stats: FunnelStats[];
}

const FunnelCard: React.FC<{ stat: FunnelStats }> = ({ stat }) => {
  const conversionLeadToMeeting = stat.leads > 0 ? (stat.meetings_scheduled / stat.leads) * 100 : 0;
  const conversionMeetingToSale = stat.meetings_realized > 0 ? (stat.sales / stat.meetings_realized) * 100 : 0;

  const cac = stat.sales > 0 ? stat.invested_amount / stat.sales : 0;
  const showCac = stat.funnel_type === FunnelType.LEAD_BROKER;

  const titleColor = 
    stat.funnel_type === FunnelType.LEAD_BROKER ? 'text-purple-700 bg-purple-50' :
    stat.funnel_type === FunnelType.OUTBOUND ? 'text-blue-700 bg-blue-50' :
    'text-orange-700 bg-orange-50';

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className={`p-4 border-b border-gray-100 ${titleColor} flex justify-between items-center`}>
        <h3 className="font-bold">{stat.funnel_type}</h3>
        {showCac && (
          <span className="text-xs bg-white bg-opacity-60 px-2 py-1 rounded shadow-sm">
            CAC: <strong>{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(cac)}</strong>
          </span>
        )}
      </div>

      <div className="p-4 space-y-4">
        {/* Funnel Steps */}
        <div className="relative">
           <div className="absolute left-3 top-0 bottom-0 w-0.5 bg-gray-100"></div>

           {/* Step 1: Leads */}
           <div className="relative flex items-center mb-4">
             <div className="bg-white border-2 border-gray-200 z-10 w-8 h-8 rounded-full flex items-center justify-center text-gray-400">
               <Users className="w-4 h-4" />
             </div>
             <div className="ml-4 flex-1">
               <p className="text-xs text-gray-500 uppercase">Leads</p>
               <p className="font-bold text-gray-800">{stat.leads}</p>
             </div>
           </div>

           {/* Step 2: Connections */}
           <div className="relative flex items-center mb-4">
            <div className="bg-white border-2 border-gray-200 z-10 w-8 h-8 rounded-full flex items-center justify-center text-gray-400">
               <Phone className="w-4 h-4" />
             </div>
             <div className="ml-4 flex-1">
               <p className="text-xs text-gray-500 uppercase">Connections</p>
               <p className="font-bold text-gray-800">{stat.connections}</p>
             </div>
           </div>

           {/* Step 3: Meetings */}
           <div className="relative flex items-center mb-4">
            <div className="bg-white border-2 border-gray-200 z-10 w-8 h-8 rounded-full flex items-center justify-center text-gray-400">
               <CalendarCheck className="w-4 h-4" />
             </div>
             <div className="ml-4 flex-1">
               <p className="text-xs text-gray-500 uppercase">Meetings (Sch / Real)</p>
               <p className="font-bold text-gray-800">{stat.meetings_scheduled} <span className="text-gray-400 font-normal">/ {stat.meetings_realized}</span></p>
             </div>
             <div className="text-right">
               <span className="text-xs font-semibold text-gray-500 bg-gray-100 px-2 py-1 rounded">{conversionLeadToMeeting.toFixed(1)}%</span>
             </div>
           </div>

           {/* Step 4: Sales */}
           <div className="relative flex items-center">
            <div className="bg-v4-red z-10 w-8 h-8 rounded-full flex items-center justify-center text-white shadow-lg">
               <CheckCircle className="w-4 h-4" />
             </div>
             <div className="ml-4 flex-1">
               <p className="text-xs text-gray-500 uppercase">Sales</p>
               <p className="font-bold text-gray-800">{stat.sales}</p>
             </div>
             <div className="text-right">
                <span className="text-xs font-semibold text-green-700 bg-green-50 px-2 py-1 rounded">{conversionMeetingToSale.toFixed(1)}%</span>
             </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export const FunnelDashboard: React.FC<FunnelDashboardProps> = ({ stats }) => {
  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
      {stats.map(stat => (
        <FunnelCard key={stat.id} stat={stat} />
      ))}
      {stats.length === 0 && <div className="col-span-3 text-center text-gray-500">No funnel data available.</div>}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AuthGuard } from './components/AuthGuard';
import { ExecutiveSummary } from './components/ExecutiveSummary';
import { DealKanban } from './components/DealKanban';
import { FunnelDashboard } from './components/FunnelDashboard';
import { UserProfile, MonthData, Deal, FunnelStats } from './types';
import { MOCK_MONTHS, MOCK_DEALS, MOCK_FUNNEL } from './mockData';
import { LayoutGrid, Users, Settings, LogOut, ChevronDown } from 'lucide-react';

// In a real app, these would come from the 'supabaseClient' via a custom hook
const useDashboardData = (monthId: string) => {
  const [loading, setLoading] = useState(true);
  const [deals, setDeals] = useState<Deal[]>([]);
  const [funnel, setFunnel] = useState<FunnelStats[]>([]);

  useEffect(() => {
    // Simulating API fetch
    setLoading(true);
    setTimeout(() => {
      setDeals(MOCK_DEALS.filter(d => d.month_id === monthId));
      setFunnel(MOCK_FUNNEL.filter(f => f.month_id === monthId));
      setLoading(false);
    }, 400); // Small delay for realism
  }, [monthId]);

  return { loading, deals, funnel };
};

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [selectedMonthId, setSelectedMonthId] = useState<string>(MOCK_MONTHS[0].id);
  const [currentTab, setCurrentTab] = useState<'dashboard' | 'funnel'>('dashboard');

  const selectedMonth = MOCK_MONTHS.find(m => m.id === selectedMonthId) || MOCK_MONTHS[0];
  const { loading, deals, funnel } = useDashboardData(selectedMonthId);

  const handleLogout = () => setUser(null);

  return (
    <AuthGuard onLogin={setUser}>
      <div className="min-h-screen bg-gray-50 text-gray-800 font-sans">

        {/* Top Navigation */}
        <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between h-16">

              {/* Logo & Brand */}
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 bg-v4-red rounded flex items-center justify-center text-white font-bold text-xl">V4</div>
                  <span className="font-bold text-lg tracking-tight text-gray-900 hidden md:block">Commercial Intelligence</span>
                </div>

                {/* Month Selector */}
                <div className="ml-8 relative group">
                  <button className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-100 transition-colors text-sm font-medium border border-gray-200">
                    <span className="text-gray-500">Context:</span>
                    <span className="text-gray-900 font-bold">{selectedMonth.name} {selectedMonth.year}</span>
                    <ChevronDown className="w-4 h-4 text-gray-400" />
                  </button>
                  {/* Dropdown */}
                  <div className="absolute top-full left-0 mt-1 w-48 bg-white rounded-lg shadow-xl border border-gray-100 hidden group-hover:block">
                    {MOCK_MONTHS.map(m => (
                      <button
                        key={m.id}
                        onClick={() => setSelectedMonthId(m.id)}
                        className={`w-full text-left px-4 py-2 text-sm hover:bg-gray-50 ${m.id === selectedMonthId ? 'text-v4-red font-bold bg-red-50' : 'text-gray-700'}`}
                      >
                        {m.name} {m.year}
                      </button>
