// Helper for status styling
const StatusBadge = ({ status }: { status: DealStatus }) => {
  if (status === DealStatus.SIGNED) {
    return <span className="px-3 py-1 rounded-full text-xs font-bold bg-red-100 text-v4-red">Assinado</span>;
  }
  if (status === DealStatus.PENDING) {
    return <span className="px-3 py-1 rounded-full text-xs font-bold bg-orange-100 text-orange-600">Pendente</span>;
  }
  return <span className="px-3 py-1 rounded-full text-xs font-bold bg-gray-100 text-gray-600">Perdido</span>;
};

// Helper for editable cells
const EditableCell = ({ 
  value, 
  type = 'text', 
  isAdmin, 
  onSave 
}: { 
  value: string | number; 
  type?: 'text' | 'number' | 'date' | 'select';
  options?: string[];
  isAdmin: boolean; 
  onSave: (val: any) => void; 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value);

  const handleBlur = () => {
    setIsEditing(false);
    if (localValue !== value) {
      onSave(type === 'number' ? Number(localValue) : localValue);
    }
  };

  if (!isEditing || !isAdmin) {
    return (
      <div 
        onClick={() => isAdmin && setIsEditing(true)} 
        className={`w-full h-full min-h-[30px] flex items-center ${isAdmin ? 'cursor-pointer hover:bg-gray-50' : ''}`}
      >
        {type === 'date' && !value ? (
           <span className="text-gray-300 text-xs italic flex items-center gap-1"><Calendar className="w-3 h-3"/> dd/mm/aaaa</span>
        ) : (
           type === 'number' ? new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 0 }).format(Number(value)) : value
        )}
      </div>
    );
  }

  return (
    <input
      autoFocus
      type={type}
      value={localValue}
      onChange={(e) => setLocalValue(e.target.value)}
      onBlur={handleBlur}
      onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
      className="w-full border border-v4-red rounded px-2 py-1 text-sm outline-none"
    />
  );
};

