import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line } from 'recharts';

interface AnnualEvolutionProps {
  months: MonthData[];
  allDeals: Deal[];
}

export const AnnualEvolution: React.FC<AnnualEvolutionProps> = ({ months, allDeals }) => {

  // Aggregate data by month
  const data = months.map(month => {
    const monthDeals = allDeals.filter(d => d.month_id === month.id && d.status === DealStatus.SIGNED);

    const mrr = monthDeals.reduce((sum, d) => sum + d.value_mrr, 0);
    const fixed = monthDeals.reduce((sum, d) => sum + d.value_fixed, 0);
    const monetization = monthDeals.reduce((sum, d) => sum + (d.value_monetization || 0), 0);

    return {
      name: month.slug,
      MRR: mrr,
      'Escopo Fechado': fixed,
      'Monetização': monetization,
      Total: mrr + fixed + monetization,
      Meta: month.unit_goal_mrr // Plotting Goal against MRR roughly
    };
  });

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  return (
    <div className="space-y-8">

      {/* Chart 1: Revenue Composition */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <h3 className="text-lg font-bold text-gray-800 mb-6 border-l-4 border-v4-red pl-3">Composição de Faturamento (Mensal)</h3>
        <div className="h-[400px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="name" />
              <YAxis tickFormatter={(val) => `R$${val/1000}k`} />
              <Tooltip formatter={(value: number) => formatCurrency(value)} />
              <Legend />
              <Bar dataKey="MRR" stackId="a" fill="#E30613" />
              <Bar dataKey="Monetização" stackId="a" fill="#F59E0B" />
              <Bar dataKey="Escopo Fechado" stackId="a" fill="#1A1A1A" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Chart 2: MRR vs Goal */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <h3 className="text-lg font-bold text-gray-800 mb-6 border-l-4 border-v4-red pl-3">Evolução MRR vs Meta</h3>
        <div className="h-[400px]">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={data}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="name" />
              <YAxis tickFormatter={(val) => `R$${val/1000}k`} />
              <Tooltip formatter={(value: number) => formatCurrency(value)} />
              <Legend />
              <Line type="monotone" dataKey="MRR" stroke="#E30613" strokeWidth={3} />
              <Line type="monotone" dataKey="Meta" stroke="#9CA3AF" strokeDasharray="5 5" />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

