import React, { useState } from 'react';
import { MonthData, Deal, DealStatus } from '../types';
import { DollarSign, TrendingUp, Target, Briefcase, Coins, Edit2 } from 'lucide-react';

interface ExecutiveSummaryProps {
  month: MonthData;
  deals: Deal[];
  isAdmin: boolean;
  onUpdateMonth: (field: keyof MonthData, value: number) => void;
}

const EditableCard: React.FC<{
  title: string;
  value: number;
  isEditable?: boolean;
  isAdmin: boolean;
  icon: React.ReactNode;
  subtitle?: React.ReactNode;
  progress?: number;
  onSave?: (val: number) => void;
}> = ({ title, value, isEditable, isAdmin, icon, subtitle, progress, onSave }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  const handleBlur = () => {
    setIsEditing(false);
    if (localValue !== value && onSave) {
      onSave(Number(localValue));
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between h-full relative group hover:border-v4-red transition-colors">
      <div className="flex justify-between items-start mb-2">
        <div>
          <p className="text-sm font-medium text-gray-500 uppercase tracking-wide flex items-center gap-2">
            {title}
            {isEditable && isAdmin && <Edit2 className="w-3 h-3 text-gray-300 opacity-0 group-hover:opacity-100" />}
          </p>

          {isEditing ? (
            <input
              autoFocus
              type="number"
              className="text-xl font-bold text-gray-900 mt-1 w-full border-b border-v4-red outline-none"
              value={localValue}
              onChange={(e) => setLocalValue(Number(e.target.value))}
              onBlur={handleBlur}
              onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
            />
          ) : (
            <h3 
              className={`text-2xl font-bold text-gray-900 mt-1 ${isEditable && isAdmin ? 'cursor-pointer hover:text-v4-red' : ''}`}
              onClick={() => isEditable && isAdmin && setIsEditing(true)}
            >
              {formatCurrency(value)}
            </h3>
          )}
        </div>
        <div className="p-2 rounded-lg bg-gray-50">
          {icon}
        </div>
      </div>

      <div>
        {subtitle}
        {progress !== undefined && (
          <div className="mt-2">
            <div className="flex justify-between text-xs text-gray-500 mb-1">
              <span>Progresso</span>
              <span>{progress.toFixed(1)}%</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2.5">
              <div 
                className={`h-2.5 rounded-full ${progress < 50 ? 'bg-red-500' : progress < 80 ? 'bg-yellow-500' : 'bg-green-500'}`} 
                style={{ width: `${Math.min(progress, 100)}%` }}
              ></div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export const ExecutiveSummary: React.FC<ExecutiveSummaryProps> = ({ month, deals, isAdmin, onUpdateMonth }) => {
  // 1. Calculate Signed MRR (Assessoria)
  const signedMRR = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_mrr, 0);

  // 2. Calculate Actual Revenue (Total Invoiced: Fixed + MRR + Monetization) for Signed deals
  const actualRevenue = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_fixed + d.value_mrr + (d.value_monetization || 0), 0);

  // 3. Monetization Actual
  const signedMonetization = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + (d.value_monetization || 0), 0);

  // 4. Progress Calculations
  const unitProgress = (signedMRR / month.unit_goal_mrr) * 100;
  const matrixProgress = (signedMRR / month.matrix_goal_mrr) * 100;

  // Monetization Progress
  const monetizationProgress = month.unit_goal_monetization > 0 ? (signedMonetization / month.unit_goal_monetization) * 100 : 0;

  return (
    <div className="space-y-6 mb-8">
      {/* Primary KPI Row */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {/* MRR (Calculated) */}
        <EditableCard 
          title="MRR Atual" 
          value={signedMRR} 
          isAdmin={isAdmin} 
          icon={<DollarSign className="w-6 h-6 text-v4-red" />}
          subtitle={<span className="text-sm text-gray-500">Soma de contratos assinados</span>}
        />

        {/* Total Revenue (Calculated) */}
        <EditableCard 
          title="Faturamento Atual" 
          value={actualRevenue} 
          isAdmin={isAdmin} 
          icon={<TrendingUp className="w-6 h-6 text-blue-600" />}
          subtitle={<span className="text-sm text-gray-500">Total (MRR + Escopo + Monet.)</span>}
        />

        {/* Unit Goal (Editable) */}
        <EditableCard 
          title="Meta da Unidade (MRR)" 
          value={month.unit_goal_mrr} 
          isEditable 
          isAdmin={isAdmin} 
          onSave={(val) => onUpdateMonth('unit_goal_mrr', val)}
          icon={<Target className="w-5 h-5 text-gray-400" />}
          progress={unitProgress}
        />

        {/* Matrix Goal (Editable) */}
        <EditableCard 
          title="Meta da Matriz (MRR)" 
          value={month.matrix_goal_mrr} 
          isEditable 
          isAdmin={isAdmin} 
          onSave={(val) => onUpdateMonth('matrix_goal_mrr', val)}
          icon={<Briefcase className="w-5 h-5 text-gray-400" />}
          progress={matrixProgress}
        />
      </div>

      {/* Monetization Specific Row */}
      <div className="bg-orange-50 rounded-xl p-4 border border-orange-100">
        <h3 className="font-bold text-orange-800 mb-4 flex items-center gap-2">
          <Coins className="w-5 h-5" /> Performance de Monetização
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
           {/* Actual Monetization */}
           <div className="bg-white p-4 rounded-lg shadow-sm">
              <p className="text-xs text-gray-500 uppercase">Monetização Atual</p>
              <p className="text-xl font-bold text-gray-800">
                {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(signedMonetization)}
              </p>
           </div>

           {/* Unit Goal Monetization */}
           <EditableCard 
              title="Meta Monetização (Unidade)"
              value={month.unit_goal_monetization || 0}
              isEditable
              isAdmin={isAdmin}
              onSave={(val) => onUpdateMonth('unit_goal_monetization', val)}
              icon={<Target className="w-4 h-4 text-orange-400" />}
              progress={monetizationProgress}
           />

           {/* Matrix Goal Monetization */}
           <EditableCard 
              title="Meta Monetização (Matriz)"
              value={month.matrix_goal_monetization || 0}
              isEditable
              isAdmin={isAdmin}
              onSave={(val) => onUpdateMonth('matrix_goal_monetization', val)}
              icon={<Briefcase className="w-4 h-4 text-orange-400" />}
              progress={month.matrix_goal_monetization > 0 ? (signedMonetization/month.matrix_goal_monetization)*100 : 0}
           />
        </div>
      </div>
    </div>
  );
};

