}

// Status Options
const STATUS_OPTIONS = [
  { value: DealStatus.SIGNED, label: 'Assinado', color: 'bg-red-100 text-v4-red' },
  { value: DealStatus.PENDING, label: 'Pendente', color: 'bg-orange-100 text-orange-600' },
  { value: DealStatus.LOST, label: 'Perdido', color: 'bg-gray-100 text-gray-600' }
];

// Channel Options
const CHANNEL_OPTIONS = Object.values(FunnelType);

const EditableCell = ({ 
  value, 
  type = 'text', 
  isAdmin, 
  onSave,
  options
}: { 
  value: string | number; 
  type?: 'text' | 'number' | 'date' | 'select';
  options?: any[]; // For select
  isAdmin: boolean; 
  onSave: (val: any) => void; 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value);

  const handleBlur = () => {
    setIsEditing(false);
    if (localValue !== value) {
      onSave(type === 'number' ? Number(localValue) : localValue);
    }
  };

  if (!isAdmin) {
    if (type === 'select' && options) {
       // Just find label
       const opt = options.find(o => o.value === value || o === value);
       return <span>{opt?.label || opt || value}</span>
    }
    return <span>{type === 'number' ? new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 0 }).format(Number(value)) : value}</span>
  }

  if (!isEditing) {
    let displayValue: React.ReactNode = value;

    if (type === 'number') {
      displayValue = new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 0 }).format(Number(value));
    } else if (type === 'date' && !value) {
      displayValue = <span className="text-gray-300 text-xs italic flex items-center gap-1"><Calendar className="w-3 h-3"/> dd/mm/aaaa</span>;
    } else if (type === 'select' && options) {
        // Special render for badges if options have color
        const selectedOpt = options.find(o => o.value === value || o === value);
        if (selectedOpt && typeof selectedOpt === 'object' && selectedOpt.color) {
            displayValue = (
                <span className={`px-3 py-1 rounded-full text-xs font-bold ${selectedOpt.color}`}>
                    {selectedOpt.label}
                </span>
            );
        } else {
            displayValue = (
                <span className="flex items-center gap-1">
                    {value} <ChevronDown className="w-3 h-3 text-gray-400" />
                </span>
            );
        }
    }

    return (
      <div 
        onClick={() => setIsEditing(true)} 
        className="w-full h-full min-h-[30px] flex items-center cursor-pointer hover:bg-gray-50 rounded px-1 -ml-1"
      >
        {displayValue}
      </div>
    );
  }

  if (type === 'select' && options) {
    return (
      <select
        autoFocus
        value={localValue}
        onChange={(e) => {
            setLocalValue(e.target.value);
            onSave(e.target.value); // Auto save on select change
            setIsEditing(false);
        }}
        onBlur={() => setIsEditing(false)}
        className="w-full border border-v4-red rounded px-2 py-1 text-sm outline-none bg-white"
      >
        {options.map((opt: any) => (
            <option key={opt.value || opt} value={opt.value || opt}>
                {opt.label || opt}
            </option>
        ))}
      </select>
    );
  }

  return (
    <input
      autoFocus
      type={type}
      value={localValue}
      onChange={(e) => setLocalValue(e.target.value)}
      onBlur={handleBlur}
      onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
      className="w-full border border-v4-red rounded px-2 py-1 text-sm outline-none"
    />
  );
};

