export enum DealStatus {
  SIGNED = 'Signed',
  PENDING = 'Pending_Na_Rua',
  LOST = 'Lost'
}

export enum DealType {
  RECURRING = 'Recurring',
  FIXED = 'Fixed',
  MIXED = 'Mixed'
}

export enum FunnelType {
  OUTBOUND = 'Outbound',
  LEAD_BROKER = 'LeadBroker',
  INDICATION = 'Indication'
}

export interface MonthData {
  id: string;
  name: string; // e.g., "October"
  year: number;
  slug: string; // e.g., "oct-2025"
  working_days: number;

  // Goals
  unit_goal_mrr: number;
  matrix_goal_mrr: number;

  // Monetization Goals
  unit_goal_monetization: number;
  matrix_goal_monetization: number;

  // Manual Overrides (if set, these override calculated values)
  manual_current_mrr?: number;
  manual_current_revenue?: number;
  manual_monetization_current?: number;
  manual_monetization_projected?: number;
}

export interface Deal {
  id: string;
  month_id: string;
  client_name: string;
  status: DealStatus;
  type: DealType;
  value_mrr: number;         // Assessoria
  value_fixed: number;       // Escopo Fechado / Venda Única
  value_monetization: number; // Monetização
  acquisition_channel: FunnelType;
  sign_date?: string;
  start_date?: string;
  segment?: string;
}

export interface FunnelStats {
  id: string;
  month_id: string;
  funnel_type: FunnelType;
  leads: number;
  connections: number;
  meetings_scheduled: number;
  meetings_realized: number;
  sales: number;
