import React, { useState } from 'react';
import { MonthData, Deal, DealStatus } from '../types';
import { DollarSign, TrendingUp, Target, Briefcase, Edit2, Coins, Users, Activity, Wallet } from 'lucide-react';

interface ExecutiveSummaryProps {
  variant: 'acquisition' | 'monetization';
  month: MonthData;
  deals: Deal[];
  isAdmin: boolean;
  onUpdateMonth: (field: keyof MonthData, value: number) => void;
}

const EditableCard: React.FC<{
  title: string;
  value: number;
  isEditable?: boolean;
  isAdmin: boolean;
  icon: React.ReactNode;
  subtitle?: React.ReactNode;
  progress?: number;
  variantColor: string;
  onSave?: (val: number) => void;
  size?: 'normal' | 'small';
}> = ({ title, value, isEditable, isAdmin, icon, subtitle, progress, variantColor, onSave, size = 'normal' }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  const handleBlur = () => {
    setIsEditing(false);
    if (localValue !== value && onSave) {
      onSave(Number(localValue));
    }
  };

  const themeClass = variantColor.replace('text-', '');

  return (
    <div className={`bg-white ${size === 'small' ? 'p-4' : 'p-6'} rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between h-full relative group hover:border-${themeClass} transition-colors`}>
      <div className="flex justify-between items-start mb-2">
        <div className="w-full">
          <p className="text-sm font-medium text-gray-500 uppercase tracking-wide flex items-center gap-2">
            {title}
            {isEditable && isAdmin && <Edit2 className="w-3 h-3 text-gray-300 opacity-0 group-hover:opacity-100" />}
          </p>

          {isEditing ? (
            <input
              autoFocus
              className={`text-${size === 'small' ? 'lg' : '2xl'} font-bold text-gray-900 mt-1 w-full bg-transparent border-none outline-none p-0 focus:ring-0 appearance-none [&::-webkit-inner-spin-button]:appearance-none`}
              value={localValue}
              onChange={(e) => setLocalValue(Number(e.target.value))}
              onBlur={handleBlur}
              onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
              style={{ MozAppearance: 'textfield' }} 
            />
          ) : (
            <h3 
              className={`text-${size === 'small' ? 'lg' : '2xl'} font-bold text-gray-900 mt-1 ${isEditable && isAdmin ? 'cursor-pointer hover:opacity-70 transition-opacity' : ''}`}
              onClick={() => isEditable && isAdmin && setIsEditing(true)}
            >
              {formatCurrency(value)}
            </h3>
          )}
        </div>
        <div className={`p-2 rounded-lg bg-gray-50 flex-shrink-0`}>
          {icon}
        </div>
      </div>

      {(subtitle || progress !== undefined) && (
        <div>
          {subtitle}
          {progress !== undefined && (
            <div className="mt-2">
              <div className="flex justify-between text-xs text-gray-500 mb-1">
                <span>Progresso</span>
                <span>{progress.toFixed(1)}%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2.5">
                <div 
                  className={`h-2.5 rounded-full ${progress < 50 ? 'bg-red-500' : progress < 80 ? 'bg-yellow-500' : 'bg-green-500'}`} 
                  style={{ width: `${Math.min(progress, 100)}%` }}
                ></div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export const ExecutiveSummary: React.FC<ExecutiveSummaryProps> = ({ variant, month, deals, isAdmin, onUpdateMonth }) => {
  const isAcquisition = variant === 'acquisition';
  const themeColor = isAcquisition ? 'text-v4-red' : 'text-amber-600';
  const brokerColor = 'text-purple-600';

  // 1. Calculate Signed Totals
  const signedMRR = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_mrr, 0);

  const signedFixed = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_fixed, 0);

  const signedMonetization = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + (d.value_monetization || 0), 0);

  const signedPendingMonetization = deals
    .filter(d => d.status === DealStatus.SIGNED || d.status === DealStatus.PENDING)
    .reduce((sum, d) => sum + (d.value_monetization || 0), 0);

  // 2. Main KPI (Card 1) - Support Manual Override for MRR/Monetization Only
  let mainKpiValue = 0;
  if (isAcquisition) {
    mainKpiValue = month.manual_current_mrr !== undefined ? month.manual_current_mrr : signedMRR;
  } else {
    mainKpiValue = month.manual_monetization_current !== undefined ? month.manual_monetization_current : signedMonetization;
  }

  const mainKpiLabel = isAcquisition ? "MRR Atual" : "Monetização Atual";
  const mainKpiField = isAcquisition ? 'manual_current_mrr' : 'manual_monetization_current';

  // 3. Secondary KPI (Card 2) - Calculated, NOT editable (as per user request for Revenue)
  // Acquisition: Total Revenue (MRR + Fixed) - Calculated
  // Monetization: Total Value (Monetization Projected) - Editable override permitted for projection
  let secondaryKpiValue = 0;
  let isSecondaryEditable = false;

  if (isAcquisition) {
    // Faturamento Atual = Calculated strictly
    secondaryKpiValue = signedMRR + signedFixed;
    isSecondaryEditable = false; 
  } else {
    // Monetization Projected = Can be override
    secondaryKpiValue = month.manual_monetization_projected !== undefined ? month.manual_monetization_projected : signedPendingMonetization;
    isSecondaryEditable = true;
  }

  const secondaryKpiLabel = isAcquisition ? "Faturamento Atual" : "Monetização Projetada";
  const secondaryKpiSub = isAcquisition ? "(MRR + Escopo Assinado)" : "(Assinado + Pendente)";
  const secondaryKpiField = 'manual_monetization_projected'; // Only used if monetization

  // 4. Goals & Progress
  const unitGoal = isAcquisition ? month.unit_goal_mrr : month.unit_goal_monetization;
  const matrixGoal = isAcquisition ? month.matrix_goal_mrr : month.matrix_goal_monetization;

  const unitProgress = unitGoal > 0 ? (mainKpiValue / unitGoal) * 100 : 0;
  const matrixProgress = matrixGoal > 0 ? (mainKpiValue / matrixGoal) * 100 : 0;

  // 5. Lead Broker Logic
  const brokerPlanned = month.broker_planned_investment || 0;
  const brokerRealized = month.broker_realized_investment || 0;
  const brokerLeads = month.broker_leads_bought || 0;
  const brokerCPL = brokerLeads > 0 ? brokerRealized / brokerLeads : 0;

  return (
    <div className="space-y-6 mb-8">
      {/* Title */}
      <h2 className={`text-xl font-bold flex items-center gap-2 ${themeColor}`}>
        {isAcquisition ? <Briefcase className="w-6 h-6" /> : <Coins className="w-6 h-6" />}
        {isAcquisition ? "Resumo de Aquisição" : "Resumo de Monetização"}
      </h2>

      {/* Main KPI Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {/* KPI 1: MRR/Monetization Current */}
        <EditableCard 
          title={mainKpiLabel} 
          value={mainKpiValue} 
          isAdmin={isAdmin}
          isEditable={true} 
          variantColor={themeColor}
          onSave={(val) => onUpdateMonth(mainKpiField as keyof MonthData, val)}
          icon={isAcquisition ? <DollarSign className={`w-6 h-6 ${themeColor}`} /> : <Coins className={`w-6 h-6 ${themeColor}`} />}
          subtitle={<span className="text-xs text-gray-500">Contratos assinados (ou Manual)</span>}
        />

        {/* KPI 2: Revenue/Projection */}
        <EditableCard 
          title={secondaryKpiLabel} 
          value={secondaryKpiValue} 
          isAdmin={isAdmin} 
          isEditable={isSecondaryEditable}
          variantColor={themeColor}
          onSave={isSecondaryEditable ? (val) => onUpdateMonth(secondaryKpiField as keyof MonthData, val) : undefined}
          icon={<TrendingUp className="w-6 h-6 text-blue-600" />}
          subtitle={<span className="text-xs text-gray-500">{secondaryKpiSub}</span>}
        />

        {/* Unit Goal */}
        <EditableCard 
          title={`Meta Unidade (${isAcquisition ? 'MRR' : 'Monet.'})`} 
          value={unitGoal || 0} 
          isEditable 
          isAdmin={isAdmin} 
          variantColor={themeColor}
          onSave={(val) => onUpdateMonth(isAcquisition ? 'unit_goal_mrr' : 'unit_goal_monetization', val)}
          icon={<Target className="w-5 h-5 text-gray-400" />}
          progress={unitProgress}
        />

        {/* Matrix Goal */}
        <EditableCard 
          title={`Meta Matriz (${isAcquisition ? 'MRR' : 'Monet.'})`} 
          value={matrixGoal || 0} 
          isEditable 
          isAdmin={isAdmin} 
          variantColor={themeColor}
          onSave={(val) => onUpdateMonth(isAcquisition ? 'matrix_goal_mrr' : 'matrix_goal_monetization', val)}
          icon={<Briefcase className="w-5 h-5 text-gray-400" />}
          progress={matrixProgress}
        />
      </div>

      {/* Lead Broker Section (Acquisition Only) */}
      {isAcquisition && (
        <div className="bg-purple-50 rounded-xl p-4 border border-purple-100 mt-6">
           <h3 className="font-bold text-purple-800 mb-4 flex items-center gap-2">
             <Wallet className="w-5 h-5" /> Performance Lead Broker
           </h3>
           <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              <EditableCard 
                title="Invest. Planejado"
                value={brokerPlanned}
                isAdmin={isAdmin}
                isEditable={true}
                variantColor={brokerColor}
                onSave={(val) => onUpdateMonth('broker_planned_investment', val)}
                icon={<Activity className="w-4 h-4 text-purple-400" />}
                size="small"
              />
              <EditableCard 
                title="Invest. Realizado"
                value={brokerRealized}
                isAdmin={isAdmin}
                isEditable={true}
                variantColor={brokerColor}
                onSave={(val) => onUpdateMonth('broker_realized_investment', val)}
                icon={<Wallet className="w-4 h-4 text-purple-400" />}
                size="small"
              />
              <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 group relative hover:border-purple-600 transition-colors">
                 <div className="flex justify-between items-start">
                   <div>
                     <p className="text-sm font-medium text-gray-500 uppercase">Leads Comprados</p>
                     {isAdmin ? (
                        <input 
                           className="text-lg font-bold text-gray-900 mt-1 w-full bg-transparent border-none outline-none p-0 focus:ring-0 [&::-webkit-inner-spin-button]:appearance-none" 
                           type="number"
                           value={brokerLeads}
                           onChange={(e) => onUpdateMonth('broker_leads_bought', Number(e.target.value))}
                        />
                     ) : (
                        <h3 className="text-lg font-bold text-gray-900 mt-1">{brokerLeads}</h3>
                     )}
                   </div>
                   <div className="p-2 rounded-lg bg-gray-50"><Users className="w-4 h-4 text-purple-400" /></div>
                 </div>
              </div>
              <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                 <div className="flex justify-between items-start">
                   <div>
                     <p className="text-sm font-medium text-gray-500 uppercase">Custo por Lead (CPL)</p>
                     <h3 className="text-lg font-bold text-gray-900 mt-1">
                       {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(brokerCPL)}
                     </h3>
                   </div>
                   <div className="p-2 rounded-lg bg-gray-50"><Target className="w-4 h-4 text-purple-400" /></div>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Deal, DealStatus, FunnelType } from '../types';
import { Calendar, Plus, ChevronDown } from 'lucide-react';

interface DealTableProps {
  deals: Deal[];
  isAdmin: boolean;
  variant: 'acquisition' | 'monetization';
  onUpdateDeal: (id: string, field: keyof Deal, value: any) => void;
  onAddDeal?: () => void;
}

// Status Options
const STATUS_OPTIONS = [
  { value: DealStatus.SIGNED, label: 'Assinado', color: 'bg-green-100 text-green-700' },
  { value: DealStatus.PENDING, label: 'Pendente', color: 'bg-yellow-100 text-yellow-700' },
  { value: DealStatus.LOST, label: 'Perdido', color: 'bg-gray-100 text-gray-600' }
];

const CHANNEL_OPTIONS = Object.values(FunnelType);

const EditableCell = ({ 
  value, 
  type = 'text', 
  isAdmin, 
  onSave,
  options,
  textClass = ''
}: { 
  value: string | number; 
  type?: 'text' | 'number' | 'date' | 'select';
  options?: any[]; 
  isAdmin: boolean; 
  onSave: (val: any) => void; 
  textClass?: string;
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value);

  const handleBlur = () => {
    setIsEditing(false);
    if (localValue !== value) {
      onSave(type === 'number' ? Number(localValue) : localValue);
    }
  };

  if (!isAdmin) {
    let display = value;
    if (type === 'number') display = new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 0 }).format(Number(value));
    if (type === 'select' && options) {
         const opt = options.find(o => o.value === value || o === value);
         return <span className={opt?.color || ''}>{opt?.label || opt || value}</span>;
    }
    return <span className={textClass}>{display}</span>;
  }

  if (!isEditing) {
    let displayValue: React.ReactNode = value;

    if (type === 'number') {
      displayValue = new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 0 }).format(Number(value));
    } else if (type === 'date' && !value) {
      displayValue = <span className="text-gray-300 text-xs italic flex items-center gap-1"><Calendar className="w-3 h-3"/> dd/mm/aaaa</span>;
    } else if (type === 'select' && options) {
        const selectedOpt = options.find(o => o.value === value || o === value);
        if (selectedOpt && typeof selectedOpt === 'object' && selectedOpt.color) {
            displayValue = (
                <span className={`px-2 py-0.5 rounded text-xs font-bold ${selectedOpt.color}`}>
                    {selectedOpt.label}
                </span>
            );
        } else {
            displayValue = (
                <span className="flex items-center gap-1">
                    {value} <ChevronDown className="w-3 h-3 text-gray-400" />
                </span>
            );
        }
    }

    return (
      <div 
        onClick={() => setIsEditing(true)} 
        className={`w-full h-full min-h-[30px] flex items-center cursor-pointer hover:bg-gray-50 rounded px-1 -ml-1 ${textClass}`}
      >
        {displayValue}
      </div>
    );
  }

  if (type === 'select' && options) {
    return (
      <select
        autoFocus
        value={localValue}
        onChange={(e) => {
            setLocalValue(e.target.value);
            onSave(e.target.value); 
            setIsEditing(false);
        }}
        onBlur={() => setIsEditing(false)}
        className="w-full border border-blue-400 rounded px-2 py-1 text-sm outline-none bg-white"
      >
        {options.map((opt: any) => (
            <option key={opt.value || opt} value={opt.value || opt}>
                {opt.label || opt}
            </option>
        ))}
      </select>
    );
  }

  return (
    <input
      autoFocus
      type={type}
      value={localValue}
      onChange={(e) => setLocalValue(e.target.value)}
      onBlur={handleBlur}
      onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
      className="w-full border border-blue-400 rounded px-2 py-1 text-sm outline-none"
    />
  );
};

export const DealTable: React.FC<DealTableProps> = ({ deals, isAdmin, onUpdateDeal, variant, onAddDeal }) => {
  const isAcquisition = variant === 'acquisition';
  const themeColor = isAcquisition ? 'v4-red' : 'amber-500';
  const headerBg = isAcquisition ? 'bg-v4-red' : 'bg-amber-500';

  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);

  // Summary Calculations
  const calculateStats = (status: DealStatus) => {
    const filtered = deals.filter(d => d.status === status);
    const mrr = filtered.reduce((acc, d) => acc + d.value_mrr, 0);
    const fixed = filtered.reduce((acc, d) => acc + d.value_fixed, 0);
    const monetization = filtered.reduce((acc, d) => acc + (d.value_monetization || 0), 0);

    // For Acquisition: Total = MRR + Fixed.  For Monetization: Total = Monetization (simplify)
    const total = isAcquisition ? (mrr + fixed) : monetization;
    const col1 = isAcquisition ? mrr : monetization;
    const col2 = isAcquisition ? fixed : 0; 

    return { total, col1, col2 };
  };

  const signedStats = calculateStats(DealStatus.SIGNED);
  const pendingStats = calculateStats(DealStatus.PENDING);
  const lostStats = calculateStats(DealStatus.LOST);

  return (
    <div className="space-y-4">
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="flex justify-between items-center p-6 border-b border-gray-200 bg-white relative">
          <div className={`absolute top-0 left-0 w-full h-1 ${headerBg}`}></div>
          <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
            <span className={`text-${themeColor}`}>👥</span> Gestão de Contratos ({isAcquisition ? 'Aquisição' : 'Monetização'})
          </h2>
          {isAdmin && onAddDeal && (
            <button 
              onClick={onAddDeal}
              className={`${headerBg} text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:opacity-90 transition-opacity`}
            >
              <Plus className="w-4 h-4" /> Novo Cliente
            </button>
          )}
        </div>

        <div className="overflow-x-auto min-h-[200px]">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white text-gray-400 text-xs uppercase tracking-wider border-b border-gray-100">
                <th className="p-4 font-medium w-32">Status</th>
                <th className="p-4 font-medium">Nome do Cliente</th>
                {isAcquisition && <th className="p-4 font-medium w-40">Canal</th>}

                {/* Variant Specific Columns */}
                {isAcquisition && <th className="p-4 font-medium">Escopo Fechado (R$)</th>}
                {isAcquisition && <th className="p-4 font-medium">Assessoria (R$)</th>}

                {!isAcquisition && <th className="p-4 font-medium text-amber-700">Valor Monetização (R$)</th>}

                <th className="p-4 font-medium">Data da Assinatura</th>

                {/* Hide Start Date if Monetization */}
                {isAcquisition && <th className="p-4 font-medium">Data de Início</th>}

                <th className="p-4 font-medium">Segmento</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50 text-sm text-gray-700">
              {deals.map((deal) => (
                <tr key={deal.id} className="hover:bg-gray-50 transition-colors">
                  <td className="p-4">
                    <EditableCell 
                      value={deal.status} 
                      type="select" 
                      options={STATUS_OPTIONS}
                      isAdmin={isAdmin} 
                      onSave={(val) => onUpdateDeal(deal.id, 'status', val)} 
                    />
                  </td>
                  <td className="p-4 font-medium text-gray-900">
                    <EditableCell 
                      value={deal.client_name} 
                      isAdmin={isAdmin} 
                      onSave={(val) => onUpdateDeal(deal.id, 'client_name', val)} 
                    />
                  </td>

                  {isAcquisition && (
                    <td className="p-4 text-gray-500">
                      <EditableCell 
                        value={deal.acquisition_channel} 
                        type="select"
                        options={CHANNEL_OPTIONS}
                        isAdmin={isAdmin} 
                        onSave={(val) => onUpdateDeal(deal.id, 'acquisition_channel', val)} 
                      />
                    </td>
                  )}

                  {/* Acquisition Columns */}
                  {isAcquisition && (
                    <td className="p-4 font-mono">
                      <EditableCell 
                        value={deal.value_fixed} 
                        type="number"
                        isAdmin={isAdmin} 
                        onSave={(val) => onUpdateDeal(deal.id, 'value_fixed', val)} 
                      />
                    </td>
                  )}
                  {isAcquisition && (
                    <td className="p-4 font-mono font-semibold">
                      <EditableCell 
                        value={deal.value_mrr} 
                        type="number"
                        isAdmin={isAdmin} 
                        onSave={(val) => onUpdateDeal(deal.id, 'value_mrr', val)} 
                      />
                    </td>
                  )}

                  {/* Monetization Columns */}
                  {!isAcquisition && (
                    <td className="p-4 font-mono text-amber-700 bg-amber-50/30 font-bold">
                      <EditableCell 
                        value={deal.value_monetization || 0} 
                        type="number"
                        isAdmin={isAdmin} 
                        onSave={(val) => onUpdateDeal(deal.id, 'value_monetization', val)} 
                      />
                    </td>
                  )}

                  <td className="p-4">
                    <EditableCell 
                      value={deal.sign_date || ''} 
                      type="date"
                      isAdmin={isAdmin} 
                      onSave={(val) => onUpdateDeal(deal.id, 'sign_date', val)} 
                    />
                  </td>

                  {/* Hide Start Date if Monetization */}
                  {isAcquisition && (
                    <td className="p-4">
                      <EditableCell 
                        value={deal.start_date || ''} 
                        type="date"
                        isAdmin={isAdmin} 
                        onSave={(val) => onUpdateDeal(deal.id, 'start_date', val)} 
                      />
                    </td>
                  )}

                  <td className="p-4">
                    <EditableCell 
                      value={deal.segment || ''} 
                      isAdmin={isAdmin} 
                      onSave={(val) => onUpdateDeal(deal.id, 'segment', val)} 
                    />
                  </td>
                </tr>
              ))}
              {deals.length === 0 && (
                <tr>
                  <td colSpan={9} className="p-8 text-center text-gray-400 italic">
                    Nenhum contrato encontrado.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* New Summary Footer */}
        <div className="bg-gray-50 border-t border-gray-200">
           <div className="p-4 border-b border-gray-200 bg-gray-100 font-bold text-gray-700 text-sm uppercase tracking-wide">
              Resumo do Mês
           </div>

           {/* Header Row for Summary */}
           <div className="grid grid-cols-4 gap-4 px-6 py-2 text-xs font-semibold text-gray-500 uppercase">
              <div>Categoria</div>
              <div>Valor Total {isAcquisition ? '(MRR + Escopo)' : '(Monetização)'}</div>
              <div>{isAcquisition ? 'Valor MRR' : 'Valor Monetização'}</div>
              <div>{isAcquisition ? 'Valor Escopo Fechado' : '-'}</div>
           </div>

           {/* Signed Row */}
           <div className="grid grid-cols-4 gap-4 px-6 py-3 border-b border-gray-100 hover:bg-white transition-colors">
              <div className="flex items-center gap-2">
                 <div className="w-2 h-2 rounded-full bg-green-500"></div>
                 <span className="font-bold text-green-700">Assinado / Fechado</span>
              </div>
              <div className="font-mono font-bold text-gray-800">{formatCurrency(signedStats.total)}</div>
              <div className="font-mono text-gray-600">{formatCurrency(signedStats.col1)}</div>
              <div className="font-mono text-gray-600">{isAcquisition ? formatCurrency(signedStats.col2) : '-'}</div>
           </div>

           {/* Pending Row */}
           <div className="grid grid-cols-4 gap-4 px-6 py-3 border-b border-gray-100 hover:bg-white transition-colors">
              <div className="flex items-center gap-2">
                 <div className="w-2 h-2 rounded-full bg-yellow-400"></div>
                 <span className="font-bold text-yellow-700">Pendente / Na Rua</span>
              </div>
              <div className="font-mono font-bold text-gray-800">{formatCurrency(pendingStats.total)}</div>
