                    isAdmin={user?.role === 'admin'}
                    onUpdateDeal={handleUpdateDeal}
                    onAddDeal={handleAddDeal}
                 />
              </section>
            </div>
          )}

          {currentTab === 'funnel' && (
            <section className="animate-fade-in-up">
              <div className="flex justify-between items-center mb-4">
                  <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                     <Users className="w-5 h-5 text-gray-500" />
                     Performance do Funil
                  </h2>
               </div>
               <FunnelDashboard stats={currentFunnel} />
            </section>
          )}

          {currentTab === 'annual' && (
             <section className="animate-fade-in-up">
               <div className="mb-6">
                 <h2 className="text-2xl font-bold text-gray-900">Visão Anual</h2>
                 <p className="text-gray-500">Acompanhamento de performance mês a mês.</p>
               </div>
               <AnnualEvolution months={months} allDeals={allDeals} />
             </section>
          )}

        </main>
      </div>
    </AuthGuard>
  );
};

