  return (
    <div 
      draggable={isAdmin}
      onDragStart={handleDragStart}
      className={`bg-white p-4 rounded-lg shadow-sm border border-gray-100 mb-3 hover:shadow-md transition-shadow group relative ${isAdmin ? 'cursor-grab active:cursor-grabbing' : ''}`}
