import React, { useState, useEffect } from 'react';
import { AuthGuard } from './components/AuthGuard';
import { ExecutiveSummary } from './components/ExecutiveSummary';
import { DealTable } from './components/DealTable';
import { FunnelDashboard } from './components/FunnelDashboard';
import { AnnualEvolution } from './components/AnnualEvolution';
import { LeadBrokerSection } from './components/LeadBrokerSection';
import { UserProfile, Deal, FunnelStats, MonthData, DealStatus, DealType, FunnelType } from './types';
import { MOCK_MONTHS, MOCK_DEALS, MOCK_FUNNEL } from './mockData';
import { LayoutGrid, Users, LogOut, ChevronDown, BarChart3, Coins } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [selectedMonthId, setSelectedMonthId] = useState<string>(MOCK_MONTHS[0].id);
  const [currentTab, setCurrentTab] = useState<'acquisition' | 'monetization' | 'funnel' | 'annual'>('acquisition');

  // Local state for data
  const [months, setMonths] = useState<MonthData[]>(MOCK_MONTHS);
  const [allDeals, setAllDeals] = useState<Deal[]>(MOCK_DEALS);
  const [funnelData, setFunnelData] = useState<FunnelStats[]>(MOCK_FUNNEL);

  const selectedMonth = months.find(m => m.id === selectedMonthId) || months[0];

  // Filter data for current view
  const currentDeals = allDeals.filter(d => d.month_id === selectedMonthId);
  const currentFunnel = funnelData.filter(f => f.month_id === selectedMonthId);

  const handleLogout = () => setUser(null);

  // Update Deal
  const handleUpdateDeal = (id: string, field: keyof Deal, value: any) => {
    setAllDeals(prev => prev.map(d => d.id === id ? { ...d, [field]: value } : d));
  };

  // Add Deal
  const handleAddDeal = () => {
    const defaultType = currentTab === 'monetization' ? DealType.FIXED : DealType.RECURRING;
    const newDeal: Deal = {
      id: `new_${Date.now()}`,
      month_id: selectedMonthId,
      client_name: 'Novo Cliente',
      status: DealStatus.PENDING,
      type: defaultType,
      value_mrr: 0,
      value_fixed: 0,
      value_monetization: 0,
      acquisition_channel: FunnelType.OUTBOUND,
      sign_date: '',
      start_date: '',
      segment: ''
    };

    // Using functional update to ensure no race conditions
    setAllDeals(prev => [...prev, newDeal]);
  };

