import React, { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { UserProfile, ADMIN_EMAILS } from '../types';
import { Lock, ShieldCheck, AlertCircle, Mail, Loader2 } from 'lucide-react';

interface AuthGuardProps {
  onLogin: (user: UserProfile) => void;
  children: React.ReactNode;
}

export const AuthGuard: React.FC<AuthGuardProps> = ({ onLogin, children }) => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [session, setSession] = useState<any>(null);

  useEffect(() => {
    // Check active session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session?.user?.email) {
        checkUser(session.user.email);
      }
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session?.user?.email) {
        checkUser(session.user.email);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkUser = (email: string) => {
    const lowerEmail = email.toLowerCase();
    // In a real app with RLS, the backend also enforces this, 
    // but we do a UI check here for better UX.
    if (!lowerEmail.endsWith('@v4company.com')) {
      setMessage('Access Restricted: Only @v4company.com emails allowed.');
      supabase.auth.signOut();
      return;
    }

    const role = ADMIN_EMAILS.includes(lowerEmail) ? 'admin' : 'viewer';
    onLogin({ email: lowerEmail, role });
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    const lowerEmail = email.toLowerCase();

    if (!lowerEmail.endsWith('@v4company.com')) {
      setMessage('Acesso restrito a emails @v4company.com');
      setLoading(false);
      return;
    }

    const { error } = await supabase.auth.signInWithOtp({
      email: lowerEmail,
      options: {
        emailRedirectTo: window.location.origin,
      },
    });

    if (error) {
      setMessage(error.message);
    } else {
      setMessage('Link de acesso enviado! Verifique seu email.');
    }
    setLoading(false);
  };

  if (session) {
    return <>{children}</>;
  }

  return (
    <div className="min-h-screen bg-neutral-900 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
        <div className="bg-v4-red h-2 w-full"></div>
        <div className="p-8">
          <div className="flex justify-center mb-6">
            <div className="bg-red-50 p-3 rounded-full">
              <Lock className="w-8 h-8 text-v4-red" />
            </div>
          </div>

          <h2 className="text-2xl font-bold text-center text-gray-800 mb-2">
            Commercial Intelligence
          </h2>
          <p className="text-center text-gray-500 mb-8 text-sm">
            Acesso Restrito V4 Company
          </p>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Email Corporativo
              </label>
              <div className="relative">
                <input
                  type="email"
                  required
                  className="w-full pl-10 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-v4-red focus:border-transparent outline-none transition-all"
                  placeholder="nome@v4company.com"
                  value={email}
                  onChange={(e) => {
                    setEmail(e.target.value);
                    setMessage('');
                  }}
                />
                <Mail className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
            </div>

            {message && (
              <div className={`flex items-center gap-2 text-sm p-3 rounded-lg ${message.includes('enviado') ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-600'}`}>
                <AlertCircle className="w-4 h-4" />
                {message}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-v4-red text-white font-bold py-3 rounded-lg hover:bg-red-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShieldCheck className="w-5 h-5" />}
              {loading ? 'Enviando...' : 'Receber Link de Acesso'}
            </button>
          </form>

          <div className="mt-6 text-center text-xs text-gray-400 border-t border-gray-100 pt-4">
            Funciona apenas com domínios @v4company.com
          </div>
        </div>
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { MonthData, Deal, FunnelStats } from '../types';
import { MOCK_MONTHS } from '../mockData';

export const useSupabaseData = (userEmail?: string) => {
  const [months, setMonths] = useState<MonthData[]>([]);
  const [deals, setDeals] = useState<Deal[]>([]);
  const [funnelStats, setFunnelStats] = useState<FunnelStats[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    try {
      setLoading(true);

      // 1. Fetch Months
      let { data: monthsData, error: monthsError } = await supabase
        .from('months')
        .select('*')
        .order('id', { ascending: true });

      if (monthsError) throw monthsError;

      // Seed months if empty (First run)
      if (!monthsData || monthsData.length === 0) {
         console.log("Seeding months...");
         const { data, error } = await supabase.from('months').insert(MOCK_MONTHS).select();
         if (error) {
             console.error("Error seeding:", error);
         } else {
             monthsData = data;
         }
      }

      if (monthsData) setMonths(monthsData);

      // 2. Fetch Deals
      const { data: dealsData, error: dealsError } = await supabase
        .from('deals')
        .select('*');

      if (dealsError) throw dealsError;
      if (dealsData) setDeals(dealsData);

      // 3. Fetch Funnel
      const { data: funnelData, error: funnelError } = await supabase
        .from('funnel_stats')
        .select('*');

      if (funnelError) throw funnelError;
      if (funnelData) setFunnelStats(funnelData);

    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (userEmail) {
      fetchData();
    }
  }, [userEmail]);

  // CRUD OPERATIONS

  const updateMonth = async (id: string, field: keyof MonthData, value: any) => {
    // Optimistic Update
    setMonths(prev => prev.map(m => m.id === id ? { ...m, [field]: value } : m));

    const { error } = await supabase.from('months').update({ [field]: value }).eq('id', id);
    if (error) {
      console.error('Error updating month:', error);
      fetchData(); // Revert on error
    }
  };

  const updateDeal = async (id: string, field: keyof Deal, value: any) => {
    // Optimistic Update
    setDeals(prev => prev.map(d => d.id === id ? { ...d, [field]: value } : d));

    const { error } = await supabase.from('deals').update({ [field]: value }).eq('id', id);
    if (error) {
      console.error('Error updating deal:', error);
      fetchData();
    }
  };

  const addDeal = async (deal: Partial<Deal>) => {
     // Remove temp ID if present, let DB generate UUID
     const { id, ...dealData } = deal as any;

     const { data, error } = await supabase.from('deals').insert(dealData).select();
     if (error) {
         console.error('Error creating deal', error);
         return;
     }
     if (data) {
         setDeals(prev => [...prev, data[0]]);
     }
  };

  const updateFunnel = async (id: string, field: keyof FunnelStats, value: any) => {
    // Optimistic Update
    setFunnelStats(prev => prev.map(f => f.id === id ? { ...f, [field]: value } : f));

    // Check if ID is temp (created in frontend for display but doesn't exist in DB yet)
    if (id.startsWith('temp_')) {
        // We can't update a temp row, we must INSERT it. 
        // Logic handled in App.tsx or we need to pass full object here.
        // For simplicity, we assume rows exist or are created on demand.
        return;
    }

    const { error } = await supabase.from('funnel_stats').update({ [field]: value }).eq('id', id);
    if (error) {
        console.error('Error updating funnel:', error);
        fetchData();
    }
  };

  const createFunnelStats = async (stats: Partial<FunnelStats>) => {
      const { id, ...cleanStats } = stats as any;
      const { data, error } = await supabase.from('funnel_stats').insert(cleanStats).select();
      if (error) {
          console.error("Error creating funnel stat", error);
          return null;
      }
      if (data) {
          setFunnelStats(prev => [...prev, data[0]]);
          return data[0];
      }
  };

  return {
    months,
    deals,
    funnelStats,
    loading,
    updateMonth,
    updateDeal,
    addDeal,
    updateFunnel,
    createFunnelStats,
    refresh: fetchData
  };
};

