import { createClient } from '@supabase/supabase-js';

// Access environment variables using Vite's import.meta.env
const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseAnonKey) {
  console.warn(
    'Supabase environment variables are missing. Please set VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY in your .env file or Vercel project settings.'
  );
}

// Create the client with fallback values to prevent immediate crash on import.
// Connection errors will be handled in AuthGuard or data hooks.
export const supabase = createClient(
  supabaseUrl || 'https://placeholder.supabase.co',
  supabaseAnonKey || 'placeholder-key'
);

import React, { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { UserProfile, ADMIN_EMAILS } from '../types';
import { Lock, ShieldCheck, AlertCircle, Mail, Loader2, Database } from 'lucide-react';

interface AuthGuardProps {
  onLogin: (user: UserProfile) => void;
  children: React.ReactNode;
}

export const AuthGuard: React.FC<AuthGuardProps> = ({ onLogin, children }) => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [session, setSession] = useState<any>(null);
  const [configError, setConfigError] = useState(false);

  useEffect(() => {
    // Check active session and connection
    const initAuth = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();
        if (error) throw error;

        setSession(session);
        if (session?.user?.email) {
          checkUser(session.user.email);
        }
      } catch (err: any) {
        console.error("Auth initialization error:", err);
        // If "Failed to fetch", it likely means Supabase URL is invalid or blocked
        if (err.message === 'Failed to fetch' || !import.meta.env.VITE_SUPABASE_URL) {
          setConfigError(true);
        }
      }
    };

    initAuth();

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session?.user?.email) {
        checkUser(session.user.email);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkUser = (email: string) => {
    const lowerEmail = email.toLowerCase();
    // In a real app with RLS, the backend also enforces this, 
    // but we do a UI check here for better UX.
    if (!lowerEmail.endsWith('@v4company.com')) {
      setMessage('Access Restricted: Only @v4company.com emails allowed.');
      supabase.auth.signOut();
      return;
    }

    const role = ADMIN_EMAILS.includes(lowerEmail) ? 'admin' : 'viewer';
    onLogin({ email: lowerEmail, role });
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    const lowerEmail = email.toLowerCase();

    if (!lowerEmail.endsWith('@v4company.com')) {
      setMessage('Acesso restrito a emails @v4company.com');
      setLoading(false);
      return;
    }

    try {
      const { error } = await supabase.auth.signInWithOtp({
        email: lowerEmail,
        options: {
          emailRedirectTo: window.location.origin,
        },
      });

      if (error) throw error;
      setMessage('Link de acesso enviado! Verifique seu email.');
    } catch (err: any) {
      if (err.message === 'Failed to fetch') {
         setMessage('Erro de conexão. Verifique a configuração do Supabase.');
         setConfigError(true);
      } else {
         setMessage(err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  if (configError) {
    return (
      <div className="min-h-screen bg-gray-900 flex items-center justify-center p-4">
        <div className="bg-white max-w-lg w-full rounded-xl shadow-2xl p-8 text-center">
           <div className="flex justify-center mb-4">
