import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured, IS_DEMO_MODE } from '../supabaseClient';
import { UserProfile, ADMIN_EMAILS } from '../types';
import { Lock, ShieldCheck, AlertCircle, Mail, Loader2, Database, LayoutTemplate } from 'lucide-react';

interface AuthGuardProps {
  onLogin: (user: UserProfile) => void;
  children: React.ReactNode;
}

export const AuthGuard: React.FC<AuthGuardProps> = ({ onLogin, children }) => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [session, setSession] = useState<any>(null);
  const [configError, setConfigError] = useState(false);

  useEffect(() => {
    // Check if configuration exists
    if (!isSupabaseConfigured) {
      setConfigError(true);
      return;
    }

    // Attempt to recover session if it exists (optional, mostly for consistency)
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session) {
          setSession(session);
          if (session.user.email) {
            checkUser(session.user.email);
          }
        }
      } catch (err) {
        console.error("Auth init error", err);
      }
    };
    initAuth();
  }, []);

  const checkUser = (email: string) => {
    const lowerEmail = email.toLowerCase();

    // Check Domain
    if (!lowerEmail.endsWith('@v4company.com')) {
      setMessage('Acesso restrito a emails @v4company.com');
      return;
    }

    // Determine Role
    const role = ADMIN_EMAILS.includes(lowerEmail) ? 'admin' : 'viewer';

    // Grant Access Immediately
    onLogin({ email: lowerEmail, role });
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    const lowerEmail = email.toLowerCase();

    // 1. Simple Domain Validation
    if (!lowerEmail.endsWith('@v4company.com')) {
      setMessage('É necessário um e-mail @v4company.com para acessar.');
      setLoading(false);
      return;
    }

    // 2. Direct Access (Bypass OTP/Magic Link)
    // We simulate a network delay for UX, then log the user in directly.
    setTimeout(() => {
      setLoading(false);
      checkUser(lowerEmail);
    }, 600);
  };

  if (configError && !IS_DEMO_MODE) {
    return (
      <div className="min-h-screen bg-gray-900 flex items-center justify-center p-4">
        <div className="bg-white max-w-lg w-full rounded-xl shadow-2xl p-8 text-center">
           <div className="flex justify-center mb-4">
             <div className="bg-red-100 p-3 rounded-full">
               <Database className="w-8 h-8 text-red-600" />
             </div>
           </div>
           <h2 className="text-2xl font-bold text-gray-800 mb-2">Configuração Pendente</h2>
           <p className="text-gray-600 mb-6">
             Não foi possível conectar ao banco de dados. Verifique as chaves de API.
           </p>
           <button 
             onClick={() => window.location.reload()}
             className="bg-v4-red text-white px-6 py-2 rounded-lg font-bold hover:bg-red-700 transition-colors"
           >
             Tentar Novamente
           </button>
        </div>
      </div>
    );
  }

  // If we have a session from a previous real login, just pass through
  if (session) {
    return <>{children}</>;
  }

  return (
    <div className="min-h-screen bg-neutral-900 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden relative">
        <div className="bg-v4-red h-2 w-full"></div>

        {IS_DEMO_MODE && (
          <div className="absolute top-4 right-4 bg-yellow-100 text-yellow-800 text-xs font-bold px-2 py-1 rounded border border-yellow-200 flex items-center gap-1">
             <LayoutTemplate className="w-3 h-3" /> DEMO MODE
          </div>
        )}

        <div className="p-8">
          <div className="flex justify-center mb-6">
            <div className="bg-red-50 p-3 rounded-full">
              <Lock className="w-8 h-8 text-v4-red" />
            </div>
          </div>

          <h2 className="text-2xl font-bold text-center text-gray-800 mb-2">
            V4 Prates Hanzava
          </h2>
          <p className="text-center text-gray-500 mb-8 text-sm">
            Commercial Intelligence Platform
          </p>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Email Corporativo
              </label>
              <div className="relative">
                <input
                  type="email"
                  required
                  className="w-full pl-10 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-v4-red focus:border-transparent outline-none transition-all"
                  placeholder="seu.nome@v4company.com"
                  value={email}
                  onChange={(e) => {
                    setEmail(e.target.value);
                    setMessage('');
                  }}
                />
                <Mail className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" />
              </div>
            </div>

            {message && (
              <div className="flex items-center gap-2 text-sm p-3 rounded-lg bg-red-50 text-red-600">
                <AlertCircle className="w-4 h-4" />
                {message}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-v4-red text-white font-bold py-3 rounded-lg hover:bg-red-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShieldCheck className="w-5 h-5" />}
              {loading ? 'Acessando...' : 'Acessar Plataforma'}
            </button>
          </form>

          {/* Removed restriction text as requested */}
        </div>
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { supabase, IS_DEMO_MODE } from '../supabaseClient';
import { MonthData, Deal, FunnelStats, DealStatus } from '../types';
import { MOCK_MONTHS, MOCK_DEALS, MOCK_FUNNEL } from '../mockData';

export const useSupabaseData = (userEmail?: string) => {
  const [months, setMonths] = useState<MonthData[]>([]);
  const [deals, setDeals] = useState<Deal[]>([]);
  const [funnelStats, setFunnelStats] = useState<FunnelStats[]>([]);
  const [loading, setLoading] = useState(true);

  const loadMockData = () => {
    console.log("Using Offline/Mock Data fallback");
    setMonths(MOCK_MONTHS);
    setDeals(MOCK_DEALS);
    setFunnelStats(MOCK_FUNNEL);
    setLoading(false);
  };

  const fetchData = async () => {
    setLoading(true);

    // --- DEMO MODE CHECK ---
    if (IS_DEMO_MODE) {
      setTimeout(loadMockData, 600);
      return;
    }

    // --- REAL MODE: SUPABASE FETCH ---
    try {
      // 1. Fetch Months
      let { data: monthsData, error: monthsError } = await supabase
        .from('months')
        .select('*')
        .order('id', { ascending: true });

      // Handle table not found or connection error by falling back
      if (monthsError) {
        console.warn("Supabase Fetch Error (using fallback):", monthsError.message);
        loadMockData();
        return;
      }

      // If DB is connected but empty, try to seed
      if (!monthsData || monthsData.length === 0) {
         console.log("Database empty. Attempting to seed...");
         const { data, error } = await supabase.from('months').insert(MOCK_MONTHS).select();

         // If seeding fails (likely due to RLS/Permission denied for Anon users), load mocks locally
         if (error) {
             console.warn("Seeding failed (RLS blocking Anon write). Loading local data only.", error);
             loadMockData();
             return;
         } else {
             monthsData = data;
         }
      }

      if (monthsData && monthsData.length > 0) {
        setMonths(monthsData);

        // 2. Fetch Deals
        const { data: dealsData } = await supabase.from('deals').select('*');
        if (dealsData) setDeals(dealsData);

        // 3. Fetch Funnel
        const { data: funnelData } = await supabase.from('funnel_stats').select('*');
        if (funnelData) setFunnelStats(funnelData);

        setLoading(false);
      } else {
        // Fallback if data is still somehow empty
        loadMockData();
      }

    } catch (error) {
      console.error('Critical Error fetching data:', error);
      loadMockData();
    }
  };

  useEffect(() => {
    if (userEmail) {
      fetchData();
    }
  }, [userEmail]);

  // --- CRUD OPERATIONS ---

  const updateMonth = async (id: string, field: keyof MonthData, value: any) => {
    setMonths(prev => prev.map(m => m.id === id ? { ...m, [field]: value } : m));
    if (!IS_DEMO_MODE) await supabase.from('months').update({ [field]: value }).eq('id', id);
  };

  const updateDeal = async (id: string, field: keyof Deal, value: any) => {
    setDeals(prev => prev.map(d => d.id === id ? { ...d, [field]: value } : d));
    if (!IS_DEMO_MODE) await supabase.from('deals').update({ [field]: value }).eq('id', id);
  };

  const addDeal = async (deal: Partial<Deal>) => {
     // Local Optimistic Update first
     const tempId = `temp_${Date.now()}`;
     const newDealOptimistic = { ...deal, id: tempId } as Deal;
     setDeals(prev => [...prev, newDealOptimistic]);

     if (!IS_DEMO_MODE) {
       const { id, ...dealData } = deal as any;
       const { data, error } = await supabase.from('deals').insert(dealData).select();

       if (error) {
           console.error('Error persisting deal:', error);
       } else if (data) {
           // Replace temp ID with real ID
           setDeals(prev => prev.map(d => d.id === tempId ? data[0] : d));
       }
     }
  };

  const updateFunnel = async (id: string, field: keyof FunnelStats, value: any) => {
    setFunnelStats(prev => prev.map(f => f.id === id ? { ...f, [field]: value } : f));
    if (!IS_DEMO_MODE && !id.startsWith('temp_')) {
        await supabase.from('funnel_stats').update({ [field]: value }).eq('id', id);
    }
  };

  const createFunnelStats = async (stats: Partial<FunnelStats>) => {
      const tempId = `temp_${stats.funnel_type}`;
      const newStat = { ...stats, id: tempId } as FunnelStats;
      setFunnelStats(prev => [...prev, newStat]); // Optimistic

      if (!IS_DEMO_MODE) {
        const { id, ...cleanStats } = stats as any;
        const { data, error } = await supabase.from('funnel_stats').insert(cleanStats).select();
        if (data) {
           setFunnelStats(prev => prev.map(f => f.id === tempId ? data[0] : f));
           return data[0];
        }
        if (error) console.error("Error creating funnel stat", error);
      }
      return newStat;
  };

  return {
    months,
    deals,
    funnelStats,
    loading,
    updateMonth,
    updateDeal,
    addDeal,
    updateFunnel,
    createFunnelStats,
    refresh: fetchData
  };
};

import React, { useState, useEffect } from 'react';
import { AuthGuard } from './components/AuthGuard';
import { ExecutiveSummary } from './components/ExecutiveSummary';
import { DealTable } from './components/DealTable';
import { FunnelDashboard } from './components/FunnelDashboard';
import { AnnualEvolution } from './components/AnnualEvolution';
import { LeadBrokerSection } from './components/LeadBrokerSection';
import { DealBrokerSection } from './components/DealBrokerSection';
import { UserProfile, Deal, FunnelStats, MonthData, DealStatus, DealType, FunnelType } from './types';
import { useSupabaseData } from './hooks/useSupabaseData';
import { LayoutGrid, Users, LogOut, ChevronDown, ChevronRight, BarChart3, Coins, CalendarDays, Loader2, AlertCircle } from 'lucide-react';
import { supabase } from './supabaseClient';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [currentTab, setCurrentTab] = useState<'acquisition' | 'monetization' | 'funnel' | 'annual'>('acquisition');
  const [selectedMonthId, setSelectedMonthId] = useState<string>(''); // Set after load
  const [isMonthSelectorOpen, setIsMonthSelectorOpen] = useState(false);
  const [expandedYear, setExpandedYear] = useState<number | null>(2025);

  // Supabase Data Hook
  const { 
    months, deals: allDeals, funnelStats: allFunnelStats, loading, 
    updateMonth, updateDeal, addDeal, updateFunnel, createFunnelStats 
  } = useSupabaseData(user?.email);

  // Set default month once data loads
  useEffect(() => {
    if (months.length > 0) {
      if (!selectedMonthId) {
        // Try to find current month, else first
        const today = new Date();
        const currentId = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}`;
        const found = months.find(m => m.id === currentId);
        setSelectedMonthId(found ? found.id : months[0].id);
      }
    }
  }, [months, selectedMonthId]);

  const selectedMonth = months.find(m => m.id === selectedMonthId);
  const currentDeals = allDeals.filter(d => d.month_id === selectedMonthId);

  // Group months by year for selector
  const years = Array.from(new Set(months.map(m => m.year))).sort();

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUser(null);
  };

  // --- Handlers ---

  const handleUpdateDeal = (id: string, field: keyof Deal, value: any) => {
    updateDeal(id, field, value);
  };

  const handleAddDeal = () => {
    const defaultType = currentTab === 'monetization' ? DealType.FIXED : DealType.RECURRING;
    const newDeal: Partial<Deal> = {
      month_id: selectedMonthId,
      client_name: 'Novo Cliente',
      status: DealStatus.PENDING,
      type: defaultType,
      value_mrr: 0,
      value_fixed: 0,
      value_monetization: 0,
      acquisition_channel: FunnelType.OUTBOUND,
      sign_date: undefined,
      start_date: undefined,
      segment: ''
    };
    addDeal(newDeal);
  };

  const handleUpdateMonth = (field: keyof MonthData, value: number) => {
    if (selectedMonthId) {
        updateMonth(selectedMonthId, field, value);
    }
  };

  const handleUpdateFunnel = async (id: string, field: keyof FunnelStats, value: number) => {
    // If it's a temp ID, it means the record doesn't exist in DB yet.
    if (id.startsWith('temp_')) {
        const type = id.replace('temp_', '') as FunnelType;
        const newStat = await createFunnelStats({
            month_id: selectedMonthId,
            funnel_type: type,
            [field]: value
        });
        // The UI will update automatically via the hook's refresh or state update
    } else {
        updateFunnel(id, field, value);
    }
  };

  // Helper to ensure funnel stats exist for UI even if DB is empty
  const getFunnelStatsForRender = () => {
      // Define all required types
      const types = [FunnelType.OUTBOUND, FunnelType.LEAD_BROKER, FunnelType.INDICATION];

      return types.map(type => {
          const existing = allFunnelStats.find(f => f.month_id === selectedMonthId && f.funnel_type === type);
          if (existing) return existing;

          // Return placeholder structure that triggers CREATE on first edit
          return {
            id: `temp_${type}`,
            month_id: selectedMonthId,
            funnel_type: type,
            leads: 0, leads_worked: 0, calls: 0, call_duration_minutes: 0,
            connections: 0, meetings_scheduled: 0, meetings_realized: 0, sales: 0, invested_amount: 0
          } as FunnelStats;
      });
  };

  if (!user) {
      return <AuthGuard onLogin={setUser}>{null}</AuthGuard>;
  }

  // --- LOADING STATE ---
  if (loading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
              <div className="flex flex-col items-center gap-4">
                  <Loader2 className="w-8 h-8 text-v4-red animate-spin" />
                  <p className="text-gray-500 font-medium">Carregando dados...</p>
              </div>
          </div>
      );
  }

  // --- ERROR/EMPTY STATE ---
  // If we finished loading but have no month data (should be rare with fallback)
  if (!selectedMonth) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
             <div className="text-center p-8 bg-white rounded-xl shadow-lg max-w-md">
                <AlertCircle className="w-12 h-12 text-yellow-500 mx-auto mb-4" />
                <h2 className="text-xl font-bold text-gray-900 mb-2">Nenhum dado encontrado</h2>
                <p className="text-gray-600 mb-6">Não foi possível carregar os dados mensais. Verifique a conexão com o banco de dados.</p>
                <button 
                  onClick={() => window.location.reload()}
                  className="bg-v4-red text-white px-6 py-2 rounded-lg font-bold"
                >
                  Recarregar
                </button>
             </div>
          </div>
      );
  }

  return (
      <div className="min-h-screen bg-gray-50 text-gray-800 font-sans">
        {/* Top Navigation */}
        <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between h-16">

              {/* Logo & Brand */}
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 bg-v4-red rounded flex items-center justify-center text-white font-bold text-xl">V4</div>
                  <span className="font-bold text-lg tracking-tight text-gray-900 hidden md:block">Prates Hanzava</span>
                </div>

                {/* Month Selector (Only show if not in Annual view) */}
                {currentTab !== 'annual' && (
                  <div className="ml-8 relative">
                    <button 
                      onClick={() => setIsMonthSelectorOpen(!isMonthSelectorOpen)}
                      className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-100 transition-colors text-sm font-medium border border-gray-200 bg-white"
                    >
                      <CalendarDays className="w-4 h-4 text-gray-500" />
                      <span className="text-gray-900 font-bold">{selectedMonth.name} {selectedMonth.year}</span>
                      <ChevronDown className="w-4 h-4 text-gray-400" />
                    </button>

                    {/* Nested Dropdown */}
                    {isMonthSelectorOpen && (
                      <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-gray-200 overflow-hidden z-50 animate-fade-in-down">
                        {years.map(year => (
                          <div key={year} className="border-b border-gray-100 last:border-0">
                            <button 
                              onClick={() => setExpandedYear(expandedYear === year ? null : year)}
                              className={`w-full flex items-center justify-between px-4 py-2 text-sm font-bold text-left hover:bg-gray-50 transition-colors ${expandedYear === year ? 'text-v4-red' : 'text-gray-700'}`}
                            >
                              {year}
                              {expandedYear === year ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3 text-gray-400" />}
                            </button>

                            {/* Months List */}
                            {expandedYear === year && (
                              <div className="bg-gray-50 py-1">
                                {months.filter(m => m.year === year).map(m => (
                                  <button
                                    key={m.id}
                                    onClick={() => {
                                      setSelectedMonthId(m.id);
                                      setIsMonthSelectorOpen(false);
                                    }}
                                    className={`w-full text-left px-8 py-2 text-sm transition-colors ${m.id === selectedMonthId ? 'text-v4-red font-bold bg-white border-l-2 border-v4-red' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'}`}
                                  >
                                    {m.name}
                                  </button>
                                ))}
                              </div>
                            )}
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Backdrop to close */}
                    {isMonthSelectorOpen && (
                      <div 
                        className="fixed inset-0 z-40 bg-transparent" 
                        onClick={() => setIsMonthSelectorOpen(false)}
                      ></div>
                    )}
                  </div>
                )}
              </div>

              {/* Navigation Tabs */}
              <div className="hidden md:flex bg-gray-100 p-1 rounded-lg self-center overflow-x-auto">
                <button 
                  onClick={() => setCurrentTab('acquisition')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'acquisition' ? 'bg-white shadow-sm text-v4-red font-bold' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <LayoutGrid className="w-4 h-4" />
                  Aquisição
                </button>
                <button 
                  onClick={() => setCurrentTab('monetization')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'monetization' ? 'bg-white shadow-sm text-amber-600 font-bold' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <Coins className="w-4 h-4" />
                  Monetização
                </button>
                <button 
                  onClick={() => setCurrentTab('funnel')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'funnel' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <Users className="w-4 h-4" />
                  Funil
                </button>
                <button 
                  onClick={() => setCurrentTab('annual')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'annual' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <BarChart3 className="w-4 h-4" />
                  Evolução
                </button>
              </div>

              {/* User Info */}
              <div className="flex items-center gap-3 pl-4 border-l border-gray-200">
                 <div className="text-right hidden sm:block">
                   <p className="text-xs font-medium text-gray-500">{user?.role === 'admin' ? 'Administrator' : 'Viewer'}</p>
                   <p className="text-sm font-bold text-gray-900">{user?.email.split('@')[0]}</p>
