          value={signedMRR} 
          isAdmin={isAdmin}
          isEditable={false} 
          variantColor="text-blue-600"
          icon={<Briefcase className="w-5 h-5 text-blue-400" />}
        />

        {/* Card 3: Fixed (Escopo) Only */}
        <EditableCard 
          title={isAcquisition ? "Escopo (Novo)" : "Escopo (Novo)"} 
          value={signedFixed} 
          isAdmin={isAdmin} 
          isEditable={false} 
          variantColor="text-purple-600"
          icon={<PieChart className="w-5 h-5 text-purple-400" />}
        />

        {/* Card 4: Forecast / Pending */}
        <EditableCard 
          title="Na Rua (Forecast)" 
          value={pendingTotal} 
          isAdmin={isAdmin} 
          isEditable={false} 
          variantColor="text-yellow-600"
          icon={<Target className="w-5 h-5 text-yellow-500" />}
          subtitle={<span className="text-xs text-gray-400">Pendente de assinatura</span>}
