  } = useSupabaseData(user?.email);

  // Set default month once data loads
  useEffect(() => {
    if (months.length > 0) {
      if (!selectedMonthId) {
        // Try to find current month, else first
        const today = new Date();
        const currentId = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}`;
        const found = months.find(m => m.id === currentId);
        setSelectedMonthId(found ? found.id : months[0].id);
      }
    }
  }, [months, selectedMonthId]);

  const selectedMonth = months.find(m => m.id === selectedMonthId);

  // FILTER DEALS BY TAB:
  // - Acquisition: show deals with pipeline_type='acquisition' OR null/undefined (legacy)
  // - Monetization: show deals with pipeline_type='monetization'
  const currentDeals = allDeals.filter(d => {
      const isMonetizationTab = currentTab === 'monetization';

      // Match ID
      if (d.month_id !== selectedMonthId) return false;

      // Match Pipeline Type
      if (isMonetizationTab) {
          return d.pipeline_type === 'monetization';
      } else {
          // Acquisition Tab (Default)
          return d.pipeline_type === 'acquisition' || !d.pipeline_type;
      }
  });

  // Group months by year for selector
  const years = Array.from(new Set(months.map(m => m.year))).sort();

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUser(null);
  };

  // --- Handlers ---
  const handleUpdateDeal = (id: string, field: keyof Deal, value: any) => {
    updateDeal(id, field, value);
  };

  const handleAddDeal = () => {
    // Determine Pipeline Type
    const pipelineType = currentTab === 'monetization' ? 'monetization' : 'acquisition';

    // Determine Default Deal Type
    const defaultDealType = DealType.RECURRING;

    const newDeal: Partial<Deal> = {
      month_id: selectedMonthId,
      pipeline_type: pipelineType,
      client_name: currentTab === 'monetization' ? 'Novo Contrato Monetização' : 'Novo Cliente',
      status: DealStatus.PENDING,
      type: defaultDealType,
      value_mrr: 0,
      value_fixed: 0,
      acquisition_channel: FunnelType.OUTBOUND,
      sign_date: undefined,
      start_date: undefined,
      segment: ''
    };
    addDeal(newDeal);
  };

  const handleUpdateMonth = (field: keyof MonthData, value: number) => {
    if (selectedMonthId) {
        updateMonth(selectedMonthId, field, value);
    }
  };

  const handleUpdateFunnel = async (id: string, field: keyof FunnelStats, value: number) => {
    if (id.startsWith('temp_')) {
        const type = id.replace('temp_', '') as FunnelType;
        await createFunnelStats({
            month_id: selectedMonthId,
            funnel_type: type,
            [field]: value
        });
    } else {
        updateFunnel(id, field, value);
    }
  };

  const getFunnelStatsForRender = () => {
      const types = [FunnelType.OUTBOUND, FunnelType.LEAD_BROKER, FunnelType.INDICATION];
      return types.map(type => {
          const existing = allFunnelStats.find(f => f.month_id === selectedMonthId && f.funnel_type === type);
          if (existing) return existing;
          return {
            id: `temp_${type}`,
            month_id: selectedMonthId,
            funnel_type: type,
            leads: 0, leads_worked: 0, calls: 0, call_duration_minutes: 0,
            connections: 0, meetings_scheduled: 0, meetings_realized: 0, sales: 0, invested_amount: 0
          } as FunnelStats;
      });
  };

  if (!user) {
      return <AuthGuard onLogin={setUser}>{null}</AuthGuard>;
  }

  if (loading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
              <div className="flex flex-col items-center gap-4">
                  <Loader2 className="w-8 h-8 text-v4-red animate-spin" />
                  <p className="text-gray-500 font-medium">Sincronizando dados...</p>
              </div>
          </div>
      );
  }

  if (error) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
          <div className="bg-white max-w-lg w-full rounded-xl shadow-2xl p-8 text-center border-t-4 border-red-600">
             <div className="flex justify-center mb-6">
               <div className="bg-red-100 p-4 rounded-full">
                 <WifiOff className="w-10 h-10 text-red-600" />
               </div>
             </div>
             <h2 className="text-2xl font-bold text-gray-800 mb-2">Falha na Sincronização</h2>
             <p className="text-gray-600 mb-6">
               Não foi possível conectar ao banco de dados global. 
               <br/><br/>
               <span className="text-sm bg-gray-100 p-2 rounded text-gray-700 font-mono">{error}</span>
             </p>
             <button 
               onClick={() => refresh()}
               className="bg-v4-red text-white px-8 py-3 rounded-lg font-bold hover:bg-red-700 transition-colors w-full"
             >
               Tentar Novamente
             </button>
          </div>
        </div>
      );
  }

  if (!selectedMonth) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-gray-50">
             <div className="text-center p-8 bg-white rounded-xl shadow-lg max-w-md">
                <AlertCircle className="w-12 h-12 text-yellow-500 mx-auto mb-4" />
                <h2 className="text-xl font-bold text-gray-900 mb-2">Nenhum dado encontrado</h2>
                <button onClick={() => refresh()} className="bg-v4-red text-white px-6 py-2 rounded-lg font-bold">Recarregar</button>
             </div>
          </div>
      );
  }

  return (
      <div className="min-h-screen bg-gray-50 text-gray-800 font-sans">
        {/* Top Navigation */}
        <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between h-16">

              {/* Logo & Brand */}
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 bg-v4-red rounded flex items-center justify-center text-white font-bold text-xl">V4</div>
                  <span className="font-bold text-lg tracking-tight text-gray-900 hidden md:block">Prates Hanzava</span>
                </div>

                {/* Month Selector */}
                {currentTab !== 'annual' && (
                  <div className="ml-8 relative">
                    <button 
                      onClick={() => setIsMonthSelectorOpen(!isMonthSelectorOpen)}
                      className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-100 transition-colors text-sm font-medium border border-gray-200 bg-white"
                    >
                      <CalendarDays className="w-4 h-4 text-gray-500" />
                      <span className="text-gray-900 font-bold">{selectedMonth.name} {selectedMonth.year}</span>
                      <ChevronDown className="w-4 h-4 text-gray-400" />
                    </button>

                    {isMonthSelectorOpen && (
                      <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-gray-200 overflow-hidden z-50 animate-fade-in-down">
                        {years.map(year => (
                          <div key={year} className="border-b border-gray-100 last:border-0">
                            <button 
                              onClick={() => setExpandedYear(expandedYear === year ? null : year)}
                              className={`w-full flex items-center justify-between px-4 py-2 text-sm font-bold text-left hover:bg-gray-50 transition-colors ${expandedYear === year ? 'text-v4-red' : 'text-gray-700'}`}
                            >
                              {year}
                              {expandedYear === year ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3 text-gray-400" />}
                            </button>
                            {expandedYear === year && (
                              <div className="bg-gray-50 py-1">
                                {months.filter(m => m.year === year).map(m => (
                                  <button
                                    key={m.id}
                                    onClick={() => {
                                      setSelectedMonthId(m.id);
                                      setIsMonthSelectorOpen(false);
                                    }}
                                    className={`w-full text-left px-8 py-2 text-sm transition-colors ${m.id === selectedMonthId ? 'text-v4-red font-bold bg-white border-l-2 border-v4-red' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'}`}
                                  >
                                    {m.name}
                                  </button>
                                ))}
                              </div>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                     {isMonthSelectorOpen && (
                      <div className="fixed inset-0 z-40 bg-transparent" onClick={() => setIsMonthSelectorOpen(false)}></div>
                    )}
                  </div>
                )}
              </div>

              {/* Navigation Tabs */}
              <div className="hidden md:flex bg-gray-100 p-1 rounded-lg self-center overflow-x-auto">
                <button 
                  onClick={() => setCurrentTab('acquisition')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'acquisition' ? 'bg-white shadow-sm text-v4-red font-bold' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <LayoutGrid className="w-4 h-4" />
                  Aquisição
                </button>
                <button 
                  onClick={() => setCurrentTab('monetization')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'monetization' ? 'bg-white shadow-sm text-amber-600 font-bold' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <Coins className="w-4 h-4" />
                  Monetização
                </button>
                <button 
                  onClick={() => setCurrentTab('funnel')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'funnel' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <Users className="w-4 h-4" />
                  Funil
                </button>
                <button 
                  onClick={() => setCurrentTab('annual')}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all whitespace-nowrap ${currentTab === 'annual' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}
                >
                  <BarChart3 className="w-4 h-4" />
                  Evolução
                </button>
              </div>

              {/* User Info */}
              <div className="flex items-center gap-3 pl-4 border-l border-gray-200">
                 <div className="text-right hidden sm:block">
                   <p className="text-xs font-medium text-gray-500">{user?.role === 'admin' ? 'Administrator' : 'Viewer'}</p>
                   <p className="text-sm font-bold text-gray-900">{user?.email.split('@')[0]}</p>
                 </div>
                 <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-bold ${user?.role === 'admin' ? 'bg-v4-red' : 'bg-gray-400'}`}>
                   {user?.email[0].toUpperCase()}
                 </div>
                 <button onClick={handleLogout} className="p-2 text-gray-400 hover:text-v4-red transition-colors" title="Logout">
                   <LogOut className="w-5 h-5" />
                 </button>
              </div>
            </div>
          </div>
        </nav>

        {/* Main Content */}
        <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

          {currentTab === 'acquisition' && (
            <div className="animate-fade-in-up">
              <section>
                <ExecutiveSummary 
                  variant="acquisition"
                  month={selectedMonth} 
                  deals={currentDeals} 
                  isAdmin={user?.role === 'admin'}
                  onUpdateMonth={handleUpdateMonth}
                />
              </section>
              <section className="mt-8">
                 <DealTable 
                    variant="acquisition"
                    deals={currentDeals} 
                    isAdmin={user?.role === 'admin'}
                    onUpdateDeal={handleUpdateDeal}
                    onAddDeal={handleAddDeal}
                 />
              </section>
              <section className="mt-8">
                 <LeadBrokerSection 
                   month={selectedMonth}
                   isAdmin={user?.role === 'admin'}
                   onUpdateMonth={handleUpdateMonth}
                 />
              </section>
              <section className="mt-8">
                 <DealBrokerSection 
                   month={selectedMonth}
                   deals={currentDeals} 
                   isAdmin={user?.role === 'admin'}
                   onUpdateMonth={handleUpdateMonth}
                 />
              </section>
            </div>
          )}

          {currentTab === 'monetization' && (
            <div className="animate-fade-in-up">
              <section>
                <ExecutiveSummary 
                  variant="monetization"
                  month={selectedMonth} 
                  deals={currentDeals} 
                  isAdmin={user?.role === 'admin'}
                  onUpdateMonth={handleUpdateMonth}
                />
              </section>
              <section className="mt-8">
                 <DealTable 
                    variant="monetization"
                    deals={currentDeals} 
                    isAdmin={user?.role === 'admin'}
                    onUpdateDeal={handleUpdateDeal}
                    onAddDeal={handleAddDeal}
                 />
              </section>
            </div>
          )}

          {currentTab === 'funnel' && (
            <section className="animate-fade-in-up">
              <div className="flex justify-between items-center mb-4">
                  <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                     <Users className="w-5 h-5 text-gray-500" />
                     Performance do Funil
                  </h2>
               </div>
               <FunnelDashboard 
                 stats={getFunnelStatsForRender()} 
                 deals={currentDeals}
                 isAdmin={user?.role === 'admin'} 
                 onUpdateFunnel={handleUpdateFunnel}
               />
            </section>
          )}

          {currentTab === 'annual' && (
             <section className="animate-fade-in-up">
               <div className="mb-6">
                 <h2 className="text-2xl font-bold text-gray-900">Visão Anual</h2>
                 <p className="text-gray-500">Acompanhamento de performance mês a mês. (Meses sem dados são ocultados)</p>
               </div>
               <AnnualEvolution months={months} allDeals={allDeals} funnelStats={allFunnelStats} />
             </section>
          )}

        </main>
      </div>
  );
};

export default App;

import React, { useState } from 'react';
import { MonthData, Deal, DealStatus } from '../types';
import { DollarSign, TrendingUp, Target, Briefcase, Edit2, Coins, PieChart } from 'lucide-react';

interface ExecutiveSummaryProps {
  variant: 'acquisition' | 'monetization';
  month: MonthData;
  deals: Deal[]; // These deals are already filtered by pipeline type from App.tsx
  isAdmin: boolean;
  onUpdateMonth: (field: keyof MonthData, value: number) => void;
}

// Circular Progress Component
const CircularProgress: React.FC<{ percentage: number; color: string; label: string; subLabel: string }> = ({ percentage, color, label, subLabel }) => {
  const radius = 35;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (Math.min(percentage, 100) / 100) * circumference;

  return (
    <div className="flex flex-col items-center justify-center">
      <div className="relative w-24 h-24">
        <svg className="w-full h-full transform -rotate-90">
          <circle
            cx="48"
            cy="48"
            r={radius}
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            className="text-gray-100"
          />
          <circle
            cx="48"
            cy="48"
            r={radius}
            stroke={color}
            strokeWidth="8"
            fill="transparent"
            strokeDasharray={circumference}
            strokeDashoffset={strokeDashoffset}
            strokeLinecap="round"
            className="transition-all duration-1000 ease-out"
          />
        </svg>
        <div className="absolute top-0 left-0 w-full h-full flex flex-col items-center justify-center">
          <span className="text-lg font-bold text-gray-800">{percentage.toFixed(0)}%</span>
        </div>
      </div>
      <p className="text-xs font-bold text-gray-600 mt-1 uppercase">{label}</p>
      <p className="text-[10px] text-gray-400">{subLabel}</p>
    </div>
  );
};

const EditableCard: React.FC<{
  title: string;
  value: number;
  isEditable?: boolean;
  isAdmin: boolean;
  icon: React.ReactNode;
  subtitle?: React.ReactNode;
  variantColor: string;
  onSave?: (val: number) => void;
  size?: 'normal' | 'large';
  highlight?: boolean;
}> = ({ title, value, isEditable, isAdmin, icon, subtitle, variantColor, onSave, size = 'normal', highlight }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  const handleBlur = () => {
    setIsEditing(false);
    if (localValue !== value && onSave) {
      onSave(Number(localValue));
    }
  };

  const themeClass = variantColor.replace('text-', '');

  return (
    <div className={`bg-white rounded-xl shadow-sm border ${highlight ? `border-${themeClass} bg-${themeClass}/5` : 'border-gray-100'} flex flex-col justify-between h-full relative group hover:border-${themeClass} transition-colors ${size === 'large' ? 'p-6' : 'p-5'}`}>
      <div className="flex justify-between items-start mb-2">
        <div className="w-full">
          <p className="text-sm font-medium text-gray-500 uppercase tracking-wide flex items-center gap-2">
            {title}
            {isEditable && isAdmin && <Edit2 className="w-3 h-3 text-gray-300 opacity-0 group-hover:opacity-100" />}
          </p>

          {isEditing ? (
            <input
              autoFocus
              className={`font-bold text-gray-900 mt-2 w-full bg-transparent border-none outline-none p-0 focus:ring-0 appearance-none ${size === 'large' ? 'text-3xl' : 'text-2xl'}`}
              value={localValue}
              onChange={(e) => setLocalValue(Number(e.target.value))}
              onBlur={handleBlur}
              onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
              style={{ MozAppearance: 'textfield' }} 
            />
          ) : (
            <h3 
              className={`font-bold text-gray-900 mt-2 ${size === 'large' ? 'text-3xl' : 'text-2xl'} ${isEditable && isAdmin ? 'cursor-pointer hover:opacity-70 transition-opacity' : ''}`}
              onClick={() => isEditable && isAdmin && setIsEditing(true)}
            >
              {formatCurrency(value)}
            </h3>
          )}
        </div>
        <div className={`p-3 rounded-xl ${highlight ? 'bg-white shadow-sm' : 'bg-gray-50'} flex-shrink-0`}>
          {icon}
        </div>
      </div>

      {subtitle && <div className="mt-1">{subtitle}</div>}
    </div>
  );
};

export const ExecutiveSummary: React.FC<ExecutiveSummaryProps> = ({ variant, month, deals, isAdmin, onUpdateMonth }) => {
  const isAcquisition = variant === 'acquisition';
  const themeColor = isAcquisition ? 'text-v4-red' : 'text-amber-600';
  const hexColor = isAcquisition ? '#E30613' : '#d97706';

  // 1. CALCULATIONS
  // "Fechado no Mês" (Signed New Deals from THIS pipeline)
  const signedMRR = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_mrr, 0);

  const signedFixed = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_fixed, 0);

  const closedThisMonth = signedMRR + signedFixed;

  // "Faturamento Atual" (Math Item 1)
  // Logic: Base Revenue (Manual Input) + Closed This Month (MRR + Fixed)
  const baseRevenue = month.manual_base_revenue || 0;
  const currentTotalRevenue = baseRevenue + closedThisMonth;

  // Goals
  // Using 'unit_goal_total' for both views as the main revenue target
  const unitGoal = month.unit_goal_total || 1;
  const matrixGoal = month.matrix_goal_total || 1;

  const unitProgress = (currentTotalRevenue / unitGoal) * 100;
  const matrixProgress = (currentTotalRevenue / matrixGoal) * 100;

  // Pending (Na Rua)
  const pendingTotal = deals
    .filter(d => d.status === DealStatus.PENDING)
    .reduce((sum, d) => sum + d.value_mrr + d.value_fixed, 0);

  return (
    <div className="space-y-6 mb-8">
      {/* Title */}
      <h2 className={`text-xl font-bold flex items-center gap-2 ${themeColor}`}>
        {isAcquisition ? <Briefcase className="w-6 h-6" /> : <Coins className="w-6 h-6" />}
        {isAcquisition ? "Resumo de Aquisição" : "Resumo de Monetização"}
      </h2>

      {/* ROW 1: STRATEGIC INDICATORS (2 Columns Side-by-Side) */}
      {/* Layout Logic: Acquisition = Grid 2 cols | Monetization = Flex Center (Goal Card Only) */}
      <div className={isAcquisition ? "grid grid-cols-1 md:grid-cols-2 gap-6" : "flex justify-center"}>

        {/* BLOCK 1: FATURAMENTO ATUAL (Shown only in Acquisition) */}
        {isAcquisition && (
          <EditableCard 
            title="Faturamento Atual"
            value={currentTotalRevenue}
            isEditable={true} 
            isAdmin={isAdmin}
            // Update Base Revenue when user edits total
            onSave={(val) => {
               onUpdateMonth('manual_base_revenue', val - closedThisMonth);
            }} 
            variantColor={themeColor}
            icon={<TrendingUp className={`w-8 h-8 ${themeColor}`} />}
            size="large"
            highlight
            subtitle={
              <div className="text-xs text-gray-500 mt-2 flex flex-col gap-1">
                 <span className="flex justify-between">
                    <span>Base (Recorrente + Antigos):</span> 
                    <span className="font-semibold">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(baseRevenue)}</span>
                 </span>
                 <span className="flex justify-between">
                    <span>+ Fechado no Mês (Novo):</span> 
                    <span className="font-semibold text-green-600">+{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(closedThisMonth)}</span>
                 </span>
              </div>
            }
          />
        )}

        {/* BLOCK 2: GOALS (Circles) */}
        {/* In Monetization: We wrap it to match the width of the acquisition column (50% or md:w-1/2) */}
        <div className={isAcquisition ? "h-full" : "w-full md:w-1/2"}>
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 flex flex-col justify-between h-full relative group">
             <div className="flex justify-between items-start mb-4">
                <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Atingimento de Metas</p>
                <div className="p-2 rounded-lg bg-gray-50"><Target className="w-5 h-5 text-gray-400" /></div>
             </div>

             <div className="flex items-center justify-around h-full">
                {/* Unit Goal Circle */}
                <div className="flex flex-col items-center gap-2">
                   <CircularProgress 
                      percentage={unitProgress} 
                      color={hexColor} 
                      label="Meta Unidade"
                      subLabel={new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(unitGoal)}
                   />
                   {isAdmin && (
                     <div 
                      onClick={() => {
                          const newVal = prompt("Nova Meta da Unidade:", unitGoal.toString());
                          if (newVal) onUpdateMonth('unit_goal_total', Number(newVal));
                      }}
                      className="text-[10px] text-gray-400 underline cursor-pointer hover:text-gray-600"
                     >
                       Editar Meta
                     </div>
                   )}
                </div>

                <div className="w-px h-24 bg-gray-100"></div>

                {/* Matrix Goal Circle */}
                <div className="flex flex-col items-center gap-2">
                   <CircularProgress 
                      percentage={matrixProgress} 
                      color="#1A1A1A" 
                      label="Meta Matriz" 
                      subLabel={new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(matrixGoal)}
                   />
                    {isAdmin && (
                     <div 
                      onClick={() => {
                          const newVal = prompt("Nova Meta da Matriz:", matrixGoal.toString());
                          if (newVal) onUpdateMonth('matrix_goal_total', Number(newVal));
                      }}
                      className="text-[10px] text-gray-400 underline cursor-pointer hover:text-gray-600"
                     >
                       Editar Meta
                     </div>
                   )}
                </div>
             </div>
          </div>
        </div>
      </div>

      {/* ROW 2: BREAKDOWN (4 Columns) */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">

        {/* Card 1: Fechado no Mês */}
        <EditableCard 
          title="Fechado no Mês" 
          value={closedThisMonth} 
          isAdmin={isAdmin} 
