import React, { useState } from 'react';
import { MonthData, Deal, DealStatus } from '../types';
import { DollarSign, TrendingUp, Target, Briefcase, Edit2, Coins, PieChart } from 'lucide-react';

interface ExecutiveSummaryProps {
  variant: 'acquisition' | 'monetization';
  month: MonthData;
  deals: Deal[];
  isAdmin: boolean;
  onUpdateMonth: (field: keyof MonthData, value: number) => void;
}

// Circular Progress Component - Compact Version
const CircularProgress: React.FC<{ 
  percentage: number; 
  color: string; 
  label: string; 
  subLabel: string;
  onEdit?: () => void;
  isAdmin: boolean;
}> = ({ percentage, color, label, subLabel, onEdit, isAdmin }) => {
  const radius = 28; // Reduced radius (was 35) -> Approx 60px width
  const circumference = 2 * Math.PI * radius;
  // Cap visual progress at 100% so the stroke doesn't look broken on huge numbers
  const strokeDashoffset = circumference - (Math.min(percentage, 100) / 100) * circumference;

  // Determine font size based on percentage length to prevent overflow
  const percentText = percentage.toFixed(0) + '%';
  const fontSizeClass = percentText.length > 4 ? 'text-[10px]' : 'text-xs';

  return (
    <div className="flex flex-col items-center justify-center">
      <div className="relative w-16 h-16">
        <svg className="w-full h-full transform -rotate-90">
          <circle
            cx="32"
            cy="32"
            r={radius}
            stroke="currentColor"
            strokeWidth="6"
            fill="transparent"
            className="text-gray-100"
          />
          <circle
            cx="32"
            cy="32"
            r={radius}
            stroke={color}
            strokeWidth="6"
            fill="transparent"
            strokeDasharray={circumference}
            strokeDashoffset={strokeDashoffset}
            strokeLinecap="round"
            className="transition-all duration-1000 ease-out"
          />
        </svg>
        <div className="absolute top-0 left-0 w-full h-full flex flex-col items-center justify-center">
          <span className={`font-bold text-gray-800 ${fontSizeClass}`}>{percentText}</span>
        </div>
      </div>

      {/* Label Section */}
      <div className="mt-1 text-center">
        <p className="text-[10px] font-bold text-gray-500 uppercase tracking-wide">{label}</p>

        {/* Value & Edit Button */}
        <div 
          className={`flex items-center justify-center gap-1 mt-0.5 ${isAdmin ? 'cursor-pointer hover:bg-gray-50 rounded px-1 -mx-1 transition-colors' : ''}`}
          onClick={(e) => {
            if (isAdmin && onEdit) {
              e.stopPropagation();
              onEdit();
            }
          }}
          title={isAdmin ? "Clique para editar a meta" : ""}
        >
          <p className="text-xs text-gray-800 font-semibold">{subLabel}</p>
          {isAdmin && <Edit2 className="w-3 h-3 text-gray-400" />}
        </div>
      </div>
    </div>
  );
};

const EditableCard: React.FC<{
  title: string;
  value: number;
  isEditable?: boolean;
  isAdmin: boolean;
  icon: React.ReactNode;
  subtitle?: React.ReactNode;
  variantColor: string;
  onSave?: (val: number) => void;
  size?: 'normal' | 'large';
  highlight?: boolean;
}> = ({ title, value, isEditable, isAdmin, icon, subtitle, variantColor, onSave, size = 'normal', highlight }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  const handleBlur = () => {
    setIsEditing(false);
    if (localValue !== value && onSave) {
      onSave(Number(localValue));
    }
  };

  const themeClass = variantColor.replace('text-', '');

  // Adjusted padding for more compact look
  return (
    <div className={`bg-white rounded-xl shadow-sm border ${highlight ? `border-${themeClass} bg-${themeClass}/5` : 'border-gray-100'} flex flex-col justify-between h-full relative group hover:border-${themeClass} transition-colors p-5`}>
      <div className="flex justify-between items-start mb-1">
        <div className="w-full">
          <p className="text-xs font-medium text-gray-500 uppercase tracking-wide flex items-center gap-2">
            {title}
            {isEditable && isAdmin && <Edit2 className="w-3 h-3 text-gray-300 opacity-0 group-hover:opacity-100" />}
          </p>

          {isEditing ? (
            <input
              autoFocus
              className="font-bold text-gray-900 mt-1 w-full bg-transparent border-none outline-none p-0 focus:ring-0 appearance-none text-2xl"
              value={localValue}
              onChange={(e) => setLocalValue(Number(e.target.value))}
              onBlur={handleBlur}
              onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
              style={{ MozAppearance: 'textfield' }} 
            />
          ) : (
            <h3 
              className={`font-bold text-gray-900 mt-1 text-2xl ${isEditable && isAdmin ? 'cursor-pointer hover:opacity-70 transition-opacity' : ''}`}
              onClick={() => isEditable && isAdmin && setIsEditing(true)}
            >
              {formatCurrency(value)}
            </h3>
          )}
        </div>
        <div className={`p-2 rounded-lg ${highlight ? 'bg-white shadow-sm' : 'bg-gray-50'} flex-shrink-0`}>
          {icon}
        </div>
      </div>

      {subtitle && <div className="mt-1">{subtitle}</div>}
    </div>
  );
};

