// New Vertical Progress Bar for Goals (Cleaner Layout)
const VerticalGoal: React.FC<{ 
  current: number; 
  target: number; 
  color: string; 
  label: string;
  isAdmin: boolean;
  onEdit: () => void;
}> = ({ current, target, color, label, isAdmin, onEdit }) => {
  const percent = target > 0 ? (current / target) * 100 : 0;
  // Clamp visual bar to 100% so it doesn't overflow, but show real text
  const visualPercent = Math.min(percent, 100);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  return (
    <div className="flex flex-col items-center gap-3 flex-1">
      {/* Target Label & Edit */}
      <div className="text-center flex flex-col items-center">
        <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">{label}</span>
        <button
          onClick={(e) => {
            e.stopPropagation();
            e.preventDefault();
            if (isAdmin) onEdit();
          }}
          disabled={!isAdmin}
          className={`flex items-center gap-1 mt-0.5 px-2 py-0.5 rounded transition-colors ${isAdmin ? 'hover:bg-gray-100 cursor-pointer text-gray-700' : 'text-gray-500'}`}
          title={isAdmin ? "Clique para editar a meta" : ""}
        >
           <span className="text-xs font-bold">{formatCurrency(target)}</span>
           {isAdmin && <Edit2 className="w-3 h-3 text-gray-400" />}
        </button>
      </div>

      {/* Bar */}
      <div className="relative h-20 w-6 bg-gray-100 rounded-full flex items-end overflow-hidden shadow-inner">
         <div 
           className="w-full rounded-b-full transition-all duration-1000 ease-out relative group"
           style={{ height: `${visualPercent}%`, backgroundColor: color }}
         >
         </div>
      </div>

      {/* Percent Value */}
      <span className="text-sm font-bold" style={{ color: color }}>
        {percent.toFixed(0)}%
      </span>
    </div>
  );
};

