import { useState, useEffect } from 'react';
import { supabase, IS_DEMO_MODE } from '../supabaseClient';
import { MonthData, Deal, FunnelStats } from '../types';
import { MOCK_MONTHS } from '../mockData';

export const useSupabaseData = (userEmail?: string) => {
  const [months, setMonths] = useState<MonthData[]>([]);
  const [deals, setDeals] = useState<Deal[]>([]);
  const [funnelStats, setFunnelStats] = useState<FunnelStats[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = async () => {
    setLoading(true);
    setError(null);

    // --- DEMO MODE CHECK ---
    if (IS_DEMO_MODE) {
      // Only use Mocks explicitly in Demo Mode
      const { MOCK_DEALS, MOCK_FUNNEL } = await import('../mockData');
      setMonths(MOCK_MONTHS);
      setDeals(MOCK_DEALS);
      setFunnelStats(MOCK_FUNNEL);
      setLoading(false);
      return;
    }

    // --- REAL MODE: SUPABASE FETCH ---
    try {
      // 1. Fetch Months
      let { data: monthsData, error: monthsError } = await supabase
        .from('months')
        .select('*')
        .order('id', { ascending: true });

      if (monthsError) {
        throw monthsError;
      }

      // If DB is empty, Attempt to seed Initial Structure (Months)
      // This ensures all admins see the same structure
      if (!monthsData || monthsData.length === 0) {
         console.log("Database empty. Seeding initial months structure...");
         const { data, error: seedError } = await supabase.from('months').insert(MOCK_MONTHS).select();

         if (seedError) {
             console.error("Seeding Failed:", seedError);
             throw new Error("Banco de dados vazio e falha ao inicializar. Verifique as permissões RLS no Supabase.");
         }
         monthsData = data;
      }

      if (monthsData) {
        setMonths(monthsData);

        // 2. Fetch Deals
        const { data: dealsData, error: dealsError } = await supabase.from('deals').select('*');
        if (dealsError) throw dealsError;
        if (dealsData) setDeals(dealsData);

        // 3. Fetch Funnel
        const { data: funnelData, error: funnelError } = await supabase.from('funnel_stats').select('*');
        if (funnelError) throw funnelError;
        if (funnelData) setFunnelStats(funnelData);
      }

    } catch (err: any) {
      console.error('Critical Error fetching data:', err);
      setError(err.message || "Erro desconhecido ao conectar com o banco.");
      // DO NOT FALLBACK TO MOCK DATA HERE. 
      // Falling back creates "split brain" where users think they are working but aren't syncing.
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (userEmail) {
      fetchData();
    }
  }, [userEmail]);

  // --- CRUD OPERATIONS ---

  const updateMonth = async (id: string, field: keyof MonthData, value: any) => {
    // Optimistic Update
    setMonths(prev => prev.map(m => m.id === id ? { ...m, [field]: value } : m));

    if (!IS_DEMO_MODE) {
      const { error } = await supabase.from('months').update({ [field]: value }).eq('id', id);
      if (error) {
        console.error("Failed to save Month update:", error);
        alert(`Erro ao salvar alteração: ${error.message || JSON.stringify(error)}`);
        fetchData(); // Revert/Refresh
      }
    }
  };

  const updateDeal = async (id: string, field: keyof Deal, value: any) => {
    setDeals(prev => prev.map(d => d.id === id ? { ...d, [field]: value } : d));

    if (!IS_DEMO_MODE) {
      const { error } = await supabase.from('deals').update({ [field]: value }).eq('id', id);
      if (error) {
        console.error("Failed to save Deal update:", error);
        alert("Erro ao salvar contrato. Tente novamente.");
        fetchData();
      }
    }
  };

  const addDeal = async (deal: Partial<Deal>) => {
     const tempId = `temp_${Date.now()}`;
     const newDealOptimistic = { ...deal, id: tempId } as Deal;
     setDeals(prev => [...prev, newDealOptimistic]);

     if (!IS_DEMO_MODE) {
       const { id, ...dealData } = deal as any;
       const { data, error } = await supabase.from('deals').insert(dealData).select();

       if (error) {
           console.error('Error persisting deal:', error);
           alert("Erro ao criar novo contrato.");
           setDeals(prev => prev.filter(d => d.id !== tempId)); // Remove optimistic
       } else if (data) {
           setDeals(prev => prev.map(d => d.id === tempId ? data[0] : d));
       }
     }
  };

  const updateFunnel = async (id: string, field: keyof FunnelStats, value: any) => {
    setFunnelStats(prev => prev.map(f => f.id === id ? { ...f, [field]: value } : f));

    if (!IS_DEMO_MODE && !id.startsWith('temp_')) {
        const { error } = await supabase.from('funnel_stats').update({ [field]: value }).eq('id', id);
        if (error) {
           console.error("Failed to save Funnel update:", error);
           alert("Erro ao salvar dados do funil.");
        }
    }
  };

  const createFunnelStats = async (stats: Partial<FunnelStats>) => {
      const tempId = `temp_${stats.funnel_type}`;
      const newStat = { ...stats, id: tempId } as FunnelStats;
      setFunnelStats(prev => [...prev, newStat]);

      if (!IS_DEMO_MODE) {
        const { id, ...cleanStats } = stats as any;
        const { data, error } = await supabase.from('funnel_stats').insert(cleanStats).select();
        if (data) {
           setFunnelStats(prev => prev.map(f => f.id === tempId ? data[0] : f));
           return data[0];
        }
        if (error) {
            console.error("Error creating funnel stat", error);
            alert("Erro ao inicializar dados do funil.");
        }
      }
      return newStat;
  };

  return {
    months,
    deals,
    funnelStats,
    loading,
    error,
    updateMonth,
    updateDeal,
    addDeal,
    updateFunnel,
    createFunnelStats,
    refresh: fetchData
  };
};

import React, { useState } from 'react';
import { MonthData, Deal, DealStatus } from '../types';
import { DollarSign, TrendingUp, Target, Briefcase, Edit2, Coins, PieChart, History } from 'lucide-react';

interface ExecutiveSummaryProps {
  variant: 'acquisition' | 'monetization';
  month: MonthData;
  deals: Deal[];
  isAdmin: boolean;
  onUpdateMonth: (field: keyof MonthData, value: number) => void;
}

// Vertical Progress Bar for Goals
const VerticalGoal: React.FC<{ 
  current: number; 
  target: number; 
  color: string; 
  label: string;
  isAdmin: boolean;
  onEdit: () => void;
}> = ({ current, target, color, label, isAdmin, onEdit }) => {
  const percent = target > 0 ? (current / target) * 100 : 0;
  const visualPercent = Math.min(percent, 100);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  return (
    <div className="flex flex-col items-center gap-3 flex-1 h-full justify-end">
      {/* Target Label & Edit */}
      <div className="text-center flex flex-col items-center mb-1">
        <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">{label}</span>
        <button
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
            if (isAdmin) onEdit();
          }}
          disabled={!isAdmin}
          className={`flex items-center gap-1 mt-0.5 px-2 py-1 rounded transition-colors z-10 ${isAdmin ? 'hover:bg-gray-100 cursor-pointer text-gray-700 active:bg-gray-200' : 'text-gray-500'}`}
          title={isAdmin ? "Clique para editar a meta" : ""}
          type="button"
        >
           <span className="text-xs font-bold">{formatCurrency(target)}</span>
           {isAdmin && <Edit2 className="w-3 h-3 text-gray-400" />}
        </button>
      </div>

      {/* Bar */}
      <div className="relative h-20 w-8 bg-gray-100 rounded-full flex items-end overflow-hidden shadow-inner">
         <div 
           className="w-full rounded-b-full transition-all duration-1000 ease-out relative"
           style={{ height: `${visualPercent}%`, backgroundColor: color }}
         >
         </div>
      </div>

      {/* Percent Value */}
      <span className="text-sm font-bold mt-1" style={{ color: color }}>
        {percent.toFixed(0)}%
      </span>
    </div>
  );
};

// Improved EditableCard using string state for input
const EditableCard: React.FC<{
  title: string;
  value: number;
  isEditable?: boolean;
  isAdmin: boolean;
  icon: React.ReactNode;
  subtitle?: React.ReactNode;
  variantColor: string;
  onSave?: (val: number) => void;
  highlight?: boolean;
}> = ({ title, value, isEditable, isAdmin, icon, subtitle, variantColor, onSave, highlight }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(value.toString());

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  const startEditing = () => {
    if (isEditable && isAdmin) {
      setLocalValue(value.toString());
      setIsEditing(true);
    }
  };

  const handleBlur = () => {
    setIsEditing(false);
    const parsed = parseFloat(localValue);
    if (!isNaN(parsed) && parsed !== value && onSave) {
      onSave(parsed);
    } else {
      setLocalValue(value.toString()); // Revert if invalid or no change
    }
  };

  const themeClass = variantColor.replace('text-', '');

  return (
    <div className={`bg-white rounded-xl shadow-sm border ${highlight ? `border-${themeClass} bg-${themeClass}/5` : 'border-gray-100'} flex flex-col justify-between h-full relative group hover:border-${themeClass} transition-colors p-5`}>
      <div className="flex justify-between items-start mb-1">
        <div className="w-full">
          <p className="text-xs font-medium text-gray-500 uppercase tracking-wide flex items-center gap-2">
            {title}
            {isEditable && isAdmin && <Edit2 className="w-3 h-3 text-gray-300 opacity-0 group-hover:opacity-100" />}
          </p>

          {isEditing ? (
            <input
              autoFocus
              className="font-bold text-gray-900 mt-1 w-full bg-transparent border-none outline-none p-0 focus:ring-0 appearance-none text-2xl"
              value={localValue}
              onChange={(e) => setLocalValue(e.target.value)}
              onBlur={handleBlur}
              onKeyDown={(e) => e.key === 'Enter' && handleBlur()}
              style={{ MozAppearance: 'textfield' }} 
            />
          ) : (
            <h3 
              className={`font-bold text-gray-900 mt-1 text-2xl ${isEditable && isAdmin ? 'cursor-pointer hover:opacity-70 transition-opacity' : ''}`}
              onClick={startEditing}
            >
              {formatCurrency(value)}
            </h3>
          )}
        </div>
        <div className={`p-2 rounded-lg ${highlight ? 'bg-white shadow-sm' : 'bg-gray-50'} flex-shrink-0`}>
          {icon}
        </div>
      </div>

      {subtitle && <div className="mt-1">{subtitle}</div>}
    </div>
  );
};

export const ExecutiveSummary: React.FC<ExecutiveSummaryProps> = ({ variant, month, deals, isAdmin, onUpdateMonth }) => {
  const isAcquisition = variant === 'acquisition';
  const themeColor = isAcquisition ? 'text-v4-red' : 'text-amber-600';
  const hexColor = isAcquisition ? '#E30613' : '#d97706';

  // 1. CALCULATIONS
  const signedMRR = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_mrr, 0);

  const signedFixed = deals
    .filter(d => d.status === DealStatus.SIGNED)
    .reduce((sum, d) => sum + d.value_fixed, 0);

  const closedThisMonth = signedMRR + signedFixed;

  // REVISED LOGIC:
  // "MRR Mês Anterior" comes from manual_base_revenue
  // "Faturamento Atual" = MRR Mês Anterior + Closed This Month
  const previousMonthMRR = month.manual_base_revenue || 0;
  const currentTotalRevenue = previousMonthMRR + closedThisMonth;

  // Goals (Using corrected field names)
  const unitGoal = month.unit_goal_mrr || 1;
  const matrixGoal = month.matrix_goal_mrr || 1;

  return (
