        {isAcquisition && (
          <div className="h-full">
            <EditableCard 
              title="Faturamento Atual"
              value={currentTotalRevenue}
              isEditable={false} // Calculated: Not Editable
              isAdmin={isAdmin}
              variantColor={themeColor}
