              highlight
              subtitle={
                <div className="text-xs text-gray-500 mt-1 flex flex-col gap-0.5">
                   <span className="flex justify-between items-center">
                      <span>MRR Mês Anterior:</span> 
                      <span className="font-semibold">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(previousMonthMRR)}</span>
                   </span>
                   <span className="flex justify-between items-center">
                      <span>+ Fechado no Mês (Novo):</span> 
                      <span className="font-semibold text-green-600">+{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(closedThisMonth)}</span>
                   </span>
