        <button
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
            if (isAdmin) onEdit();
          }}
          disabled={!isAdmin}
          className={`text-xs font-bold transition-colors flex items-center justify-center gap-1 mx-auto ${isAdmin ? 'hover:text-gray-900 cursor-pointer text-gray-600' : 'text-gray-600'}`}
          title={isAdmin ? "Clique para editar a meta" : ""}
          type="button"
