// Dynamic Vertical Bar Component with Inline Editing
const VerticalGoal: React.FC<{ 
  current: number; 
  target: number; 
  color: string; 
  label: string;
  isAdmin: boolean;
  onSave: (val: number) => void;
}> = ({ current, target, color, label, isAdmin, onSave }) => {
  // State for inline editing
  const [isEditing, setIsEditing] = useState(false);
  const [localValue, setLocalValue] = useState(target.toString());

  // Update local value if target changes externally
  useEffect(() => {
    setLocalValue(target.toString());
  }, [target]);

  // Determine the scale max to accommodate both target and current (with some headroom)
  const safeTarget = target || 1;
  const maxValue = Math.max(safeTarget, current) * 1.15; // 15% headroom

  const targetPercent = (safeTarget / maxValue) * 100;
  const currentPercent = (current / maxValue) * 100;

  const percentAchieved = (current / safeTarget) * 100;
  const isAchieved = current >= safeTarget;

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  const handleBlur = () => {
    setIsEditing(false);
    const parsed = parseFloat(localValue);
    if (!isNaN(parsed) && parsed !== target) {
      onSave(parsed);
    } else {
      setLocalValue(target.toString()); // Revert if invalid or no change
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleBlur();
    }
  };

  return (
    <div className="flex flex-col items-center h-full w-full max-w-[120px]">
      {/* Header / Edit - Added relative and z-20 to ensure it sits above the chart */}
      <div className="text-center mb-2 relative z-20 w-full flex flex-col items-center">
        <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider block mb-1">{label}</span>

        {isEditing ? (
           <input
             autoFocus
             type="number"
             className="w-24 text-center font-bold text-xs bg-white border border-gray-300 rounded shadow-sm outline-none px-1 py-0.5 focus:ring-1 focus:ring-blue-500"
             value={localValue}
             onChange={(e) => setLocalValue(e.target.value)}
             onBlur={handleBlur}
             onKeyDown={handleKeyDown}
           />
        ) : (
          <button
            onClick={(e) => {
              e.preventDefault();
              e.stopPropagation();
              if (isAdmin) {
                setLocalValue(target.toString());
                setIsEditing(true);
              }
            }}
            disabled={!isAdmin}
            className={`text-xs font-bold transition-colors flex items-center justify-center gap-1 mx-auto px-2 py-0.5 rounded ${isAdmin ? 'hover:bg-gray-100 cursor-pointer text-gray-700' : 'text-gray-600'}`}
            title={isAdmin ? "Clique para editar a meta" : ""}
            type="button"
          >
             {formatCurrency(target)}
             {isAdmin && <Edit2 className="w-2.5 h-2.5 text-gray-400" />}
          </button>
        )}
      </div>

      {/* Chart Container */}
      <div className="relative w-full flex-1 min-h-[140px] bg-gray-50 rounded-lg border border-gray-100 mx-auto overflow-hidden group z-10">

         {/* Grid Lines (Optional decoration) */}
         <div className="absolute inset-0 flex flex-col justify-between p-2 opacity-10 pointer-events-none">
            <div className="border-t border-gray-400 w-full"></div>
            <div className="border-t border-gray-400 w-full"></div>
            <div className="border-t border-gray-400 w-full"></div>
         </div>

         {/* Target Line Indicator */}
         <div 
            className="absolute left-0 right-0 border-t-2 border-dashed border-gray-400 z-10 flex items-center justify-end pr-1 transition-all duration-700"
            style={{ bottom: `${targetPercent}%` }}
         >
            <span className="bg-gray-100 text-[9px] text-gray-500 px-1 -mt-4 rounded border border-gray-200 shadow-sm">Meta</span>
         </div>

         {/* The Bar */}
         <div 
           className="absolute bottom-0 left-1/2 transform -translate-x-1/2 w-8 rounded-t-md transition-all duration-1000 ease-out shadow-sm"
           style={{ 
             height: `${currentPercent}%`, 
             backgroundColor: color,
             opacity: isAchieved ? 1 : 0.8
           }}
         >
            {/* Tooltip-ish Value on top of bar */}
            <div className="absolute -top-6 left-1/2 transform -translate-x-1/2 text-xs font-bold whitespace-nowrap drop-shadow-md bg-white/80 px-1 rounded" style={{ color: color }}>
               {percentAchieved.toFixed(0)}%
            </div>
         </div>
      </div>
    </div>
  );
};

