Com certeza. O erro provavelmente ocorreu porque o conteúdo anterior não estava completo.

Abaixo está o **Código SQL Completo e "À Prova de Falhas"**. Ele verifica se as tabelas já existem, cria apenas o que falta e migra os dados antigos automaticamente.

**Copie tudo abaixo e cole no SQL Editor do Supabase:**

```sql
-- 1. SETUP INICIAL DAS TABELAS (Caso não existam)
CREATE TABLE IF NOT EXISTS public.months (
    id TEXT PRIMARY KEY, -- ex: '2025-10'
    name TEXT NOT NULL,
    year INTEGER NOT NULL,
    slug TEXT NOT NULL,
    working_days INTEGER DEFAULT 22,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

CREATE TABLE IF NOT EXISTS public.deals (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    month_id TEXT REFERENCES public.months(id),
    client_name TEXT NOT NULL,
    status TEXT DEFAULT 'Pending_Na_Rua',
    type TEXT DEFAULT 'Recurring',
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

CREATE TABLE IF NOT EXISTS public.funnel_stats (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    month_id TEXT REFERENCES public.months(id),
    funnel_type TEXT NOT NULL,
    leads INTEGER DEFAULT 0,
    leads_worked INTEGER DEFAULT 0,
    calls INTEGER DEFAULT 0,
    call_duration_minutes INTEGER DEFAULT 0,
    connections INTEGER DEFAULT 0,
    meetings_scheduled INTEGER DEFAULT 0,
    meetings_realized INTEGER DEFAULT 0,
    sales INTEGER DEFAULT 0,
    invested_amount NUMERIC DEFAULT 0,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 2. ATUALIZAÇÃO DE COLUNAS (Adiciona colunas novas sem quebrar o que já existe)

-- Tabela: MONTHS
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS unit_goal_mrr NUMERIC DEFAULT 0;
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS matrix_goal_mrr NUMERIC DEFAULT 0;
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS manual_base_revenue NUMERIC DEFAULT 0;
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS unit_goal_monetization NUMERIC DEFAULT 0; -- Legacy support
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS matrix_goal_monetization NUMERIC DEFAULT 0; -- Legacy support
-- Lead Broker Cols
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS broker_planned_investment NUMERIC DEFAULT 0;
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS broker_realized_investment NUMERIC DEFAULT 0;
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS broker_leads_bought INTEGER DEFAULT 0;
-- Deal Broker Cols
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS deal_broker_investment NUMERIC DEFAULT 0;
ALTER TABLE public.months ADD COLUMN IF NOT EXISTS deal_broker_deals_bought INTEGER DEFAULT 0;

-- Tabela: DEALS
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS pipeline_type TEXT DEFAULT 'acquisition';
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS value_mrr NUMERIC DEFAULT 0;
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS value_fixed NUMERIC DEFAULT 0;
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS value_monetization NUMERIC DEFAULT 0; -- Legacy
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS acquisition_channel TEXT DEFAULT 'Outbound';
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS sign_date DATE;
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS start_date DATE;
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS segment TEXT;

-- 3. MIGRAÇÃO DE DADOS INTELIGENTE (Copia dados antigos para colunas novas)
DO $$
BEGIN
    -- Migrar Meta Unidade (Se a nova estiver vazia e a antiga tiver valor)
    UPDATE public.months
    SET unit_goal_mrr = unit_goal_monetization
    WHERE (unit_goal_mrr IS NULL OR unit_goal_mrr = 0) AND unit_goal_monetization > 0;

    -- Migrar Meta Matriz
    UPDATE public.months
    SET matrix_goal_mrr = matrix_goal_monetization
    WHERE (matrix_goal_mrr IS NULL OR matrix_goal_mrr = 0) AND matrix_goal_monetization > 0;

    -- Migrar Deals Antigos de Monetização para a nova estrutura
    -- Assume que value_monetization vai para value_fixed se não houver definição
    UPDATE public.deals
    SET value_fixed = value_monetization
    WHERE (value_fixed IS NULL OR value_fixed = 0) 
      AND value_monetization > 0;

    -- Garantir que pipeline_type tenha valor padrão 'acquisition' se estiver nulo
    UPDATE public.deals
    SET pipeline_type = 'acquisition'
    WHERE pipeline_type IS NULL;
END $$;

-- 4. SEGURANÇA (RLS - Row Level Security)
-- Habilita segurança
ALTER TABLE public.months ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.deals ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.funnel_stats ENABLE ROW LEVEL SECURITY;

-- Remove políticas antigas para evitar conflito
DROP POLICY IF EXISTS "Allow anon read" ON public.months;
DROP POLICY IF EXISTS "Allow anon insert" ON public.months;
DROP POLICY IF EXISTS "Allow anon update" ON public.months;

DROP POLICY IF EXISTS "Allow anon read" ON public.deals;
DROP POLICY IF EXISTS "Allow anon insert" ON public.deals;
DROP POLICY IF EXISTS "Allow anon update" ON public.deals;
DROP POLICY IF EXISTS "Allow anon delete" ON public.deals;

DROP POLICY IF EXISTS "Allow anon read" ON public.funnel_stats;
DROP POLICY IF EXISTS "Allow anon insert" ON public.funnel_stats;
DROP POLICY IF EXISTS "Allow anon update" ON public.funnel_stats;

-- Cria novas políticas permissivas (Para facilitar o uso, ajustável para produção depois)
CREATE POLICY "Public Read Months" ON public.months FOR SELECT USING (true);
CREATE POLICY "Public Update Months" ON public.months FOR UPDATE USING (true);
CREATE POLICY "Public Insert Months" ON public.months FOR INSERT WITH CHECK (true);

CREATE POLICY "Public Read Deals" ON public.deals FOR SELECT USING (true);
CREATE POLICY "Public Update Deals" ON public.deals FOR UPDATE USING (true);
CREATE POLICY "Public Insert Deals" ON public.deals FOR INSERT WITH CHECK (true);
CREATE POLICY "Public Delete Deals" ON public.deals FOR DELETE USING (true);

CREATE POLICY "Public Read Funnel" ON public.funnel_stats FOR SELECT USING (true);
CREATE POLICY "Public Update Funnel" ON public.funnel_stats FOR UPDATE USING (true);
CREATE POLICY "Public Insert Funnel" ON public.funnel_stats FOR INSERT WITH CHECK (true);
```

