                 />
              </section>
              <section className="mt-8">
                 <LeadBrokerSection 
                   month={selectedMonth}
                   isAdmin={user?.role === 'admin'}
                   onUpdateMonth={handleUpdateMonth}
                 />
              </section>
              <section className="mt-8">
                 <DealBrokerSection 
                   month={selectedMonth}
                   deals={currentDeals} 
                   isAdmin={user?.role === 'admin'}
                   onUpdateMonth={handleUpdateMonth}
